// ────────────────────────────────────────────────────────────────────────
// GPS 지오펜싱 — 완료 보고 제출 시점의 실제 위치와 거래처 좌표 사이의
// 거리를 계산해, 반경 안에 있는지 판정한다. PRD 7번 항목의 "목적지 반경
// 1km 이탈" 기준을 그대로 사용한다.
// ────────────────────────────────────────────────────────────────────────
const GEOFENCE_RADIUS_METERS = 1000;

/** 두 좌표 사이의 거리를 미터 단위로 계산 (Haversine formula). */
function distanceInMeters(lat1, lng1, lat2, lng2) {
  const R = 6371000; // 지구 반지름(m)
  const toRad = (deg) => (deg * Math.PI) / 180;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng / 2) ** 2;
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

/**
 * 브라우저 Geolocation API로 현재 위치를 가져온다. 권한 거부, 미지원 브라우저,
 * 타임아웃 등 어떤 이유로든 실패하면 reject 대신 { error } 형태로 resolve해서
 * 호출하는 쪽이 try/catch 없이도 안전하게 처리할 수 있게 한다.
 */
function getCurrentPosition() {
  return new Promise((resolve) => {
    if (!navigator.geolocation) {
      resolve({ error: "이 브라우저는 위치 확인을 지원하지 않습니다." });
      return;
    }
    navigator.geolocation.getCurrentPosition(
      (pos) => resolve({ lat: pos.coords.latitude, lng: pos.coords.longitude, accuracy: pos.coords.accuracy }),
      (err) => resolve({ error: err.message || "위치 권한이 거부되었거나 확인할 수 없습니다." }),
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
    );
  });
}

/**
 * 카카오내비 실행 — URL Scheme 방식이라 별도 REST API 키나 앱 등록이 필요 없다.
 *   1) 모바일에서 `kakaonavi://` 스킴으로 카카오내비 앱을 직접 띄운다(앱이 설치된
 *      기기에서는 바로 길찾기 화면으로 전환됨).
 *   2) 일정 시간(800ms) 안에 앱이 열렸다는 신호가 없으면 — 즉 앱이 없거나 PC 환경이면
 *      — 카카오맵 웹(`map.kakao.com`)의 길찾기 페이지로 자동 폴백한다.
 * 거래처 좌표가 없으면(아직 지오코딩 안 된 거래처) 좌표 없이 장소명만으로 검색되는
 * 웹 길찾기로 바로 보낸다.
 */
function openKakaoNavi(customer, fallbackName) {
  const name = encodeURIComponent((customer && customer.customerName) || fallbackName || "목적지");
  const hasCoords = customer && customer.latitude != null && customer.longitude != null;

  if (!hasCoords) {
    // 좌표가 없으면 카카오맵 장소 검색 페이지로 보낸다(앱스킴은 좌표 없이는 정확도가 떨어짐).
    window.open(`https://map.kakao.com/link/search/${name}`, "_blank");
    return;
  }

  const lat = customer.latitude;
  const lng = customer.longitude;
  const appUrl = `kakaonavi://route?ep=${lat},${lng}&by=CAR`;
  const webUrl = `https://map.kakao.com/link/to/${name},${lat},${lng}`;

  // 모바일 브라우저에서만 앱 스킴을 시도한다. PC에서는 바로 웹으로 보낸다.
  const isMobile = /Android|iPhone|iPad|iPod/i.test(navigator.userAgent);
  if (!isMobile) {
    window.open(webUrl, "_blank");
    return;
  }

  let fellBack = false;
  const fallbackTimer = setTimeout(() => {
    if (!fellBack) {
      fellBack = true;
      window.location.href = webUrl;
    }
  }, 800);

  // 페이지가 백그라운드로 전환되면(=앱이 실제로 열렸다는 뜻) 폴백을 취소한다.
  const onVisibilityChange = () => {
    if (document.hidden) {
      fellBack = true;
      clearTimeout(fallbackTimer);
      document.removeEventListener("visibilitychange", onVisibilityChange);
    }
  };
  document.addEventListener("visibilitychange", onVisibilityChange);

  window.location.href = appUrl;
}

