// ────────────────────────────────────────────────────────────────────────
// GAS(Google Apps Script) 웹앱 백엔드 연동
// ⚠️ 재배포하면 URL이 바뀔 수 있으니, 재배포할 때마다 아래 값을 교체해야 한다.
// ────────────────────────────────────────────────────────────────────────
const GAS_WEB_APP_URL =
  "https://script.google.com/macros/s/AKfycbxhq25zDbvNNAC-IwlavewL3Aijaila1rElMD5D6XOH-8h4fzDmtJ6Usob4yZEgeB6Bkw/exec";

async function callGasWebApp(payload) {
  let response;
  try {
    response = await fetch(GAS_WEB_APP_URL, {
      method: "POST",
      headers: { "Content-Type": "text/plain;charset=utf-8" },
      body: JSON.stringify(payload),
      redirect: "follow",
    });
  } catch (networkErr) {
    throw { errorCode: "NETWORK_ERROR", message: "네트워크 연결을 확인해주세요." };
  }

  if (!response.ok) {
    throw { errorCode: "SERVER_ERROR", message: `서버 오류가 발생했습니다. (status ${response.status})` };
  }

  const data = await response.json();
  if (!data.success) {
    throw { errorCode: data.error_code, message: data.message, detail: data };
  }
  return data;
}

/**
 * 사번 + 비밀번호 로그인 — GAS 백엔드(Code.gs v4)의 "login" 액션을 호출해
 * 구글 스프레드시트 "직원명부(통합)"의 비밀번호 해시와 비교한다.
 * 응답에는 home_site("changwon"|"gimhae")와 role("관리자"|"지원"|"일반")가
 * 함께 내려오며, 화면은 이 두 값으로 분기한다.
 */
async function authenticateEmployee(employeeId, password) {
  const trimmed = employeeId.trim().toUpperCase();
  if (!trimmed || !password) {
    throw { errorCode: "EMPTY_INPUT", message: "사번과 비밀번호를 모두 입력해주세요." };
  }

  const data = await callGasWebApp({ action: "login", employee_id: trimmed, password });

  return {
    employee: {
      employeeId: data.employee.employee_id,
      name: data.employee.name,
      department: data.employee.department,
      title: data.employee.title,
      role: data.employee.role,
      homeSite: data.employee.home_site,
    },
    mustChangePassword: data.must_change_password,
  };
}

/**
 * 비밀번호 변경 — GAS 백엔드의 "changePassword" 액션을 호출해
 * 직원명부(통합)의 비밀번호해시/솔트/초기비밀번호여부 컬럼을 갱신한다.
 */
async function changeEmployeePassword(employeeId, currentPassword, newPassword) {
  if (!newPassword || newPassword.length < 4) {
    throw { errorCode: "WEAK_PASSWORD", message: "비밀번호는 4자리 이상이어야 합니다." };
  }

  await callGasWebApp({
    action: "changePassword",
    employee_id: employeeId.trim().toUpperCase(),
    current_password: currentPassword,
    new_password: newPassword,
  });
}

/**
 * 창원(마산) 입출고 등록 — GAS 백엔드의 "createTransaction" 액션을 호출해
 * "입출고내역(창원)" 시트에 새 행을 추가한다. PART NO가 "자재마스터(창원)"에
 * 등록되어 있으면 품명/L·C/사업부/층수를 서버가 자동으로 채워준다.
 * actorEmployeeId는 권한 검사(일반/지원/관리자 모두 허용)에 쓰인다.
 */
async function createTransaction(actorEmployeeId, body) {
  const data = await callGasWebApp({
    action: "createTransaction",
    actor_employee_id: actorEmployeeId,
    part_no: body.partNo,
    type: body.type, // "입고" | "출고"
    quantity: body.quantity,
    pallet: body.pallet,
    vehicle_no: body.vehicleNo,
    requester: body.requester,
    temp_lc_used: body.tempLcUsed,
    temp_lc: body.tempLc,
    field_worker_name: body.fieldWorkerName,
    note: body.note, // "폐기" | "기타" | ""
    note_detail: body.noteDetail,
  });

  return {
    id: data.id,
    partNo: data.part_no,
    name: data.name,
    type: data.type,
    quantity: data.quantity,
    beforeStock: data.before_stock,
    afterStock: data.after_stock,
    date: data.date,
  };
}

/**
 * 근무지 전환 — GAS 백엔드의 "switchSite" 액션을 호출해 "지원"/"관리자"
 * 권한인지 서버에서 다시 확인한다. 실제 직원명부의 소속(B열)은 바뀌지 않고,
 * 화면에서 "오늘 어느 사이트로 볼지"만 바뀐다(브라우저를 새로고침하면
 * 원래 근무지로 돌아온다).
 */
async function switchSite(actorEmployeeId, targetSite) {
  const data = await callGasWebApp({
    action: "switchSite",
    actor_employee_id: actorEmployeeId,
    target_site: targetSite,
  });
  return { activeSite: data.active_site };
}

