/** 전체 Part No.별 현재 재고 목록 — "listStockSummary" 액션. */
async function listStockSummary() {
  const data = await callGasWebApp({ action: "listStockSummary" });
  return (data.items || []).map((row) => ({
    partNo: row.part_no,
    name: row.name,
    lc: row.lc,
    stock: row.stock,
    lastUpdated: row.last_updated,
  }));
}

/** 월별 수불표(창원) — "getMonthlyLedger" 액션. yearMonth는 "yyyy-MM" 형식. */
async function getMonthlyLedger(yearMonth) {
  const data = await callGasWebApp({ action: "getMonthlyLedger", year_month: yearMonth });
  return {
    yearMonth: data.year_month,
    items: (data.items || []).map((row) => ({
      partNo: row.part_no,
      name: row.name,
      lc: row.lc,
      openingStock: row.opening_stock,
      inQty: row.in_qty,
      outQty: row.out_qty,
      closingStock: row.closing_stock,
    })),
  };
}

/** 특정 Part No. 입출고 이력 — "listTransactions" 액션. */
async function listTransactions(filters = {}) {
  const data = await callGasWebApp({
    action: "listTransactions",
    date: filters.date,
    part_no: filters.partNo,
  });
  return (data.transactions || []).map((row) => ({
    id: row.id,
    date: row.date,
    partNo: row.part_no,
    name: row.name,
    type: row.type,
    inQty: row.in_qty,
    outQty: row.out_qty,
    stock: row.stock,
    pallet: row.pallet,
    businessUnit: row.business_unit,
    vehicleNo: row.vehicle_no,
    requester: row.requester,
    floor: row.floor,
    lc: row.lc,
    tempLcUsed: row.temp_lc_used,
    tempLc: row.temp_lc,
    fieldWorker: row.field_worker,
    note: row.note,
  }));
}

/** Part No.로 보관 층수 + 도면좌표를 조회 — "findMaterialLocation" 액션. */
