function ForcePasswordChangeScreen({ employee, onChanged, onLogout }) {
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [error, setError] = useState("");
  const [status, setStatus] = useState("idle"); // idle | saving

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (newPassword.length < 4) {
      setError("새 비밀번호는 4자리 이상이어야 합니다.");
      return;
    }
    if (newPassword === "1111") {
      setError("초기 비밀번호와 동일한 값은 사용할 수 없습니다.");
      return;
    }
    if (newPassword !== confirmPassword) {
      setError("새 비밀번호와 비밀번호 확인이 일치하지 않습니다.");
      return;
    }

    setError("");
    setStatus("saving");
    try {
      await changeEmployeePassword(employee.employeeId, "1111", newPassword);
      setStatus("idle");
      onChanged();
    } catch (err) {
      setStatus("idle");
      setError(err.message || "비밀번호 변경 중 오류가 발생했습니다.");
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-slate-50 px-4 font-sans">
      <div className="w-full max-w-sm rounded-2xl border border-slate-200 bg-white p-8 shadow-sm">
        <div className="flex flex-col items-center">
          <span className="flex h-14 w-14 items-center justify-center rounded-full" style={{ backgroundColor: BRAND.greenSoft }}>
            <KeyRound className="h-7 w-7" style={{ color: BRAND.deepGreen }} />
          </span>
          <h1 className="mt-3 text-lg font-bold text-slate-900">비밀번호 변경이 필요합니다</h1>
          <p className="mt-1 text-center text-xs text-slate-400">
            {employee.name}님은 초기 비밀번호(1111)를 사용중입니다.<br />보안을 위해 새 비밀번호로 변경해주세요.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="mt-6 space-y-4">
          <div>
            <label className="text-xs font-semibold text-slate-500">새 비밀번호</label>
            <div className="mt-1.5 flex items-center gap-2 rounded-lg border border-slate-200 px-3 py-2.5">
              <Lock className="h-4 w-4 text-slate-400" />
              <input
                type="password"
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
                placeholder="4자리 이상 입력"
                disabled={status === "saving"}
                className="w-full text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
              />
            </div>
          </div>

          <div>
            <label className="text-xs font-semibold text-slate-500">새 비밀번호 확인</label>
            <div className="mt-1.5 flex items-center gap-2 rounded-lg border border-slate-200 px-3 py-2.5">
              <Lock className="h-4 w-4 text-slate-400" />
              <input
                type="password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                placeholder="다시 입력"
                disabled={status === "saving"}
                className="w-full text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
              />
            </div>
          </div>

          {error && <p className="text-xs font-semibold text-red-500">{error}</p>}

          <button
            type="submit"
            disabled={status === "saving"}
            className="flex w-full items-center justify-center gap-2 rounded-lg py-3 text-sm font-bold text-white disabled:opacity-50"
            style={{ backgroundColor: BRAND.deepGreen }}
          >
            {status === "saving" ? "저장중..." : "비밀번호 변경"}
          </button>

          <button type="button" onClick={onLogout} className="w-full text-center text-xs font-semibold text-slate-400">
            로그아웃
          </button>
        </form>
      </div>
    </div>
  );
}

