/**
 * 알림(통합) 화면(16번 요청) — 헤더의 알림(벨) 버튼으로 들어온다.
 *   - "알림 목록" 탭: 누구나 볼 수 있다. 마산 요청/김해 업체 긴급요청은 빨간색으로
 *     강조해서 눈에 잘 띄게 한다(17·18번).
 *   - "알림 설정" 탭: 관리자/지원만 볼 수 있다. 분류별로 on/off 토글이 있고,
 *     "전체 알림"을 끄면 나머지 분류 설정과 상관없이 모든 알림이 꺼진다.
 */
function NotificationScreen({ employee, onBack }) {
  const isAdmin = isElevatedRole(employee.role);
  const [tab, setTab] = useState("feed"); // feed | settings
  const [notifications, setNotifications] = useState([]);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");
  const [settings, setSettings] = useState(null);
  const [settingsStatus, setSettingsStatus] = useState("idle");
  const [settingsError, setSettingsError] = useState("");
  const [savingKey, setSavingKey] = useState(null);

  const reloadFeed = async () => {
    setStatus("loading");
    try {
      const data = await listNotifications();
      setNotifications(data);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "알림을 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  const reloadSettings = async () => {
    setSettingsStatus("loading");
    try {
      const data = await getNotificationSettings(employee.employeeId);
      setSettings(data);
      setSettingsStatus("ready");
    } catch (err) {
      setSettingsError(err.message || "알림 설정을 불러오지 못했습니다.");
      setSettingsStatus("error");
    }
  };

  useEffect(() => { reloadFeed(); }, []);
  useEffect(() => {
    if (tab === "settings" && isAdmin && !settings) reloadSettings();
  }, [tab]);

  const toggleSetting = async (key) => {
    if (!settings) return;
    const previous = settings;
    const next = { ...settings, [key]: !settings[key] };
    setSettings(next);
    setSavingKey(key);
    try {
      await updateNotificationSettings(employee.employeeId, { [key]: next[key] });
    } catch (err) {
      setSettings(previous);
      setSettingsError(err.message || "설정 변경 중 오류가 발생했습니다.");
    } finally {
      setSavingKey(null);
    }
  };

  const isUrgentCategory = isUrgentNotificationCategory;

  const formatTimestamp = (iso) => {
    const d = new Date(iso);
    if (isNaN(d.getTime())) return iso || "";
    return d.toLocaleString("ko-KR", { month: "numeric", day: "numeric", hour: "2-digit", minute: "2-digit" });
  };

  const SETTING_GROUPS = [
    { site: "통합", items: [{ key: "all_enabled", label: "전체 알림" }] },
    { site: "마산(창원)", items: [
      { key: "changwon_transaction", label: "입출고 알림" },
      { key: "changwon_material", label: "자재 등록 알림" },
      { key: "changwon_request", label: "요청 알림" },
    ] },
    { site: "김해", items: [
      { key: "gimhae_schedule", label: "일정 등록 알림" },
      { key: "gimhae_complete", label: "완료 알림" },
      { key: "gimhae_urgent_request", label: "업체 긴급요청 알림" },
    ] },
  ];

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">알림</h1>

      <div className={`mt-4 grid gap-2 ${isAdmin ? "grid-cols-2" : "grid-cols-1"}`}>
        <button onClick={() => setTab("feed")} className={`rounded-lg py-2 text-xs font-bold ${tab === "feed" ? "text-white" : "border border-slate-200 text-slate-500"}`} style={tab === "feed" ? { backgroundColor: BRAND.deepGreen } : {}}>
          알림 목록
        </button>
        {isAdmin && (
          <button onClick={() => setTab("settings")} className={`rounded-lg py-2 text-xs font-bold ${tab === "settings" ? "text-white" : "border border-slate-200 text-slate-500"}`} style={tab === "settings" ? { backgroundColor: BRAND.deepGreen } : {}}>
            알림 설정
          </button>
        )}
      </div>

      {tab === "feed" && (
        <>
          {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
          {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}
          {status === "ready" && (
            <div className="mt-4 space-y-2">
              {notifications.length === 0 && <p className="py-8 text-center text-xs text-slate-400">알림이 없습니다.</p>}
              {notifications.map((n, idx) => {
                const urgent = isUrgentCategory(n.category);
                return (
                  <div key={idx} className={`rounded-xl border p-4 ${urgent ? "border-red-300 bg-red-50" : "border-slate-200 bg-white"}`}>
                    <div className="flex items-center justify-between gap-2">
                      <p className={`text-sm font-bold ${urgent ? "text-red-600" : "text-slate-900"}`}>{n.title}</p>
                      <span className="flex-shrink-0 text-[10px] text-slate-400">{formatTimestamp(n.timestamp)}</span>
                    </div>
                    <p className={`mt-1 text-xs ${urgent ? "text-red-700" : "text-slate-600"}`}>{n.content}</p>
                    <p className="mt-1 text-[11px] text-slate-400">{n.site} · {n.actorName || "(미확인)"}</p>
                  </div>
                );
              })}
            </div>
          )}
        </>
      )}

      {tab === "settings" && isAdmin && (
        <div className="mt-4 space-y-4">
          {settingsStatus === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
          {settingsStatus === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{settingsError}</p>}
          {settingsStatus === "ready" && settings && SETTING_GROUPS.map((group) => (
            <div key={group.site} className="rounded-xl border border-slate-200 bg-white p-4">
              <p className="text-xs font-bold text-slate-400">{group.site}</p>
              <div className="mt-2 space-y-2.5">
                {group.items.map((item) => (
                  <div key={item.key} className="flex items-center justify-between">
                    <span className="text-sm text-slate-700">{item.label}</span>
                    <button
                      onClick={() => toggleSetting(item.key)}
                      disabled={savingKey === item.key}
                      className="relative h-6 w-11 flex-shrink-0 rounded-full bg-slate-200 transition-colors disabled:opacity-50"
                      style={settings[item.key] ? { backgroundColor: BRAND.deepGreen } : {}}
                    >
                      <span className={`absolute top-0.5 h-5 w-5 rounded-full bg-white shadow transition-all ${settings[item.key] ? "left-5" : "left-0.5"}`} />
                    </button>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 공용 — 바코드 스캐너 모달.
// ZXing(@zxing/library)을 CDN에서 동적으로 불러와 사용한다. npm 패키지로
// 설치하지 않는 이유는, 이 프로젝트가 빌드 도구 없이도 동작해야 하는
// 환경(CodeSandbox 등)에서 쓰일 수 있기 때문 — <script> 동적 삽입 방식이
// 가장 환경에 무관하게 안전하게 동작한다.
// 모달이 열리면 카메라 권한을 요청하고, 바코드/QR이 인식되는 즉시
// onScan(text)을 호출한 후 자동으로 닫힌다. 권한 거부, 카메라 없음,
// 라이브러리 로드 실패 등 모든 실패 상황에서 안내 문구만 보여주고
// 부모 화면(입출고 등록)은 평소처럼 직접 타이핑할 수 있도록 막지 않는다.
// ────────────────────────────────────────────────────────────────────────
let zxingLoadPromise = null;
function loadScriptOnce(src) {
  return new Promise((resolve, reject) => {
    const script = document.createElement("script");
    script.src = src;
    script.async = true;
    script.onload = () => resolve();
    script.onerror = () => reject(new Error("스크립트 로드 실패: " + src));
    document.head.appendChild(script);
  });
}
function loadZXing() {
  if (window.ZXing) return Promise.resolve(window.ZXing);
  if (zxingLoadPromise) return zxingLoadPromise;

  const CDN_URLS = [
    "https://unpkg.com/@zxing/library@0.21.3/umd/index.min.js",
    "https://cdn.jsdelivr.net/npm/@zxing/library@0.21.3/umd/index.min.js",
  ];

  zxingLoadPromise = (async () => {
    let lastError = null;
    for (const url of CDN_URLS) {
      try {
        await loadScriptOnce(url);
        if (window.ZXing) return window.ZXing;
      } catch (err) {
        lastError = err;
      }
    }
    throw new Error("바코드 스캐너 라이브러리를 불러오지 못했습니다. 네트워크 상태를 확인해주세요.");
  })();

  return zxingLoadPromise;
}

function BarcodeScannerModal({ onScan, onClose }) {
  const videoRef = useRef(null);
  const readerRef = useRef(null);
  const [status, setStatus] = useState("loading"); // loading | scanning | error
  const [error, setError] = useState("");

  useEffect(() => {
    let cancelled = false;

    (async () => {
      try {
        const ZXing = await loadZXing();
        if (cancelled) return;

        const reader = new ZXing.BrowserMultiFormatReader();
        readerRef.current = reader;
        setStatus("scanning");

        await reader.decodeFromVideoDevice(undefined, videoRef.current, (result, err) => {
          if (cancelled) return;
          if (result) {
            const text = result.getText();
            reader.reset();
            onScan(text);
          }
          // NotFoundException은 "아직 못 찾음" 상태로, 매 프레임마다 정상적으로 발생하므로 무시한다.
        });
      } catch (err) {
        if (cancelled) return;
        setError(err.message || "카메라를 시작할 수 없습니다. 카메라 권한을 확인해주세요.");
        setStatus("error");
      }
    })();

    return () => {
      cancelled = true;
      if (readerRef.current) {
        try {
          readerRef.current.reset();
        } catch (e) {
          // 정리 중 발생하는 오류는 무시해도 안전하다.
        }
      }
    };
  }, [onScan]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 px-4">
      <div className="w-full max-w-sm rounded-2xl bg-white p-4">
        <div className="flex items-center justify-between">
          <p className="flex items-center gap-1.5 text-sm font-bold text-slate-900">
            <ScanLine className="h-4 w-4" /> 바코드 스캔
          </p>
          <button onClick={onClose} className="flex h-7 w-7 items-center justify-center rounded-full text-slate-400">
            <X className="h-4 w-4" />
          </button>
        </div>

        <div className="mt-3 overflow-hidden rounded-xl bg-slate-900" style={{ aspectRatio: "4 / 3" }}>
          <video ref={videoRef} className="h-full w-full object-cover" muted playsInline />
        </div>

        {status === "loading" && <p className="mt-3 text-center text-xs text-slate-400">카메라를 준비하는 중...</p>}
        {status === "scanning" && <p className="mt-3 text-center text-xs text-slate-400">바코드를 화면 중앙에 비춰주세요.</p>}
        {status === "error" && (
          <div className="mt-3 rounded-lg border border-red-100 bg-red-50 p-3 text-xs text-red-600">
            {error}
            <p className="mt-1 text-red-500">아래 PART NO 칸에 직접 입력해도 됩니다.</p>
          </div>
        )}
      </div>
    </div>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 창원 — 입출고 등록 화면. "장바구니" 방식: 차량번호/요청자/임시L·C 같은
// 공통 정보는 한 번만 입력해두고, PART NO·수량 등 줄마다 달라지는 정보만
// 추가해서 여러 건을 쌓은 뒤 "전체 등록"으로 한꺼번에 순차 제출한다.
// 트럭 한 대가 여러 품목을 싣고 오는 실제 현장 흐름(같은 차량번호·같은
// 요청자로 PART NO만 여러 개)에 맞춘 구조다.
// ────────────────────────────────────────────────────────────────────────
function TransactionRegisterScreen({ employee, onBack }) {
  // 공통 정보 — 장바구니의 모든 줄에 공통으로 적용됨
  const [type, setType] = useState("입고"); // "입고" | "출고"
  const [vehicleNo, setVehicleNo] = useState("");
  const [requester, setRequester] = useState("");
  const [tempLcUsed, setTempLcUsed] = useState(false);
  const [tempLc, setTempLc] = useState("");

  // 한 줄(품목) 입력 — "추가"를 누르면 장바구니로 들어가고 비워진다
  const [partNo, setPartNo] = useState("");
  const [quantity, setQuantity] = useState("");
  const [pallet, setPallet] = useState("");
  const [note, setNote] = useState(""); // "" | "폐기" | "기타"
  const [noteDetail, setNoteDetail] = useState("");
  const [lineError, setLineError] = useState("");
  const [scannerOpen, setScannerOpen] = useState(false);

  // 장바구니 — 등록 전까지 메모리에만 쌓여있는 목록
  const [cart, setCart] = useState([]);

  // 제출 진행 상태
  const [submitting, setSubmitting] = useState(false);
  const [submitProgress, setSubmitProgress] = useState(null); // { done, total }
  const [lastSummary, setLastSummary] = useState(null); // 제출 완료 후 결과 요약

  const resetLineInputs = () => {
    setPartNo("");
    setQuantity("");
    setPallet("");
    setNote("");
    setNoteDetail("");
  };

  /** 바코드 인식 결과를 PART NO 칸에 채운다. 모달은 즉시 닫고, 사용자가 한 번
   * 더 확인한 뒤 수량을 입력해 "장바구니에 추가"를 누르도록 한다(스캔만으로
   * 바로 등록까지 가지 않아, 잘못 스캔했을 때 되돌리기 쉽다). */
  const handleScanResult = (text) => {
    setPartNo(text);
    setScannerOpen(false);
    setLineError("");
  };

  const handleAddToCart = (e) => {
    e.preventDefault();
    if (!partNo.trim()) {
      setLineError("PART NO를 입력해주세요.");
      return;
    }
    const qty = Number(quantity);
    if (!qty || qty <= 0) {
      setLineError("수량은 1 이상의 숫자여야 합니다.");
      return;
    }
    setLineError("");

    setCart((prev) => [
      ...prev,
      {
        cartId: `${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
        partNo: partNo.trim(),
        quantity: qty,
        pallet,
        note,
        noteDetail,
      },
    ]);
    resetLineInputs();
  };

  const handleRemoveFromCart = (cartId) => {
    setCart((prev) => prev.filter((line) => line.cartId !== cartId));
  };

  /**
   * 장바구니를 순서대로 하나씩 제출한다. GAS doPost는 한 번에 한 건만
   * 처리하므로 Promise.all 같은 동시 호출 대신 순차 처리한다 — 같은 PART NO가
   * 여러 줄에 있을 때 재고가 꼬이지 않도록 순서를 보장하기 위함이기도 하다.
   * 실패한 줄은 장바구니에 그대로 남겨 재시도할 수 있게 하고, 성공한 줄만
   * 장바구니에서 제거한다.
   */
  const handleSubmitAll = async () => {
    if (cart.length === 0) return;
    setSubmitting(true);
    setLastSummary(null);
    setSubmitProgress({ done: 0, total: cart.length });

    const succeeded = [];
    const failed = [];

    for (let i = 0; i < cart.length; i++) {
      const line = cart[i];
      try {
        const result = await createTransaction(employee.employeeId, {
          partNo: line.partNo,
          type,
          quantity: line.quantity,
          pallet: line.pallet,
          vehicleNo,
          requester,
          tempLcUsed,
          tempLc,
          fieldWorkerName: employee.name,
          note: line.note,
          noteDetail: line.noteDetail,
        });
        succeeded.push({ line, result });
      } catch (err) {
        failed.push({ line, message: err.message || "처리 중 오류가 발생했습니다." });
      }
      setSubmitProgress({ done: i + 1, total: cart.length });
    }

    // 실패한 줄만 장바구니에 남긴다.
    setCart(failed.map((f) => f.line));
    setLastSummary({ succeeded, failed });
    setSubmitting(false);
    setSubmitProgress(null);
  };

  const totalQuantity = cart.reduce((sum, line) => sum + line.quantity, 0);

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">
        ← 홈으로
      </button>
      <h1 className="text-xl font-bold text-slate-900">입출고 등록</h1>
      <p className="mt-1 text-sm text-slate-400">창원(마산)공장 · {employee.name}{employee.title}</p>

      <div className="mt-5 grid grid-cols-2 gap-2">
        {["입고", "출고"].map((t) => (
          <button
            key={t}
            type="button"
            onClick={() => setType(t)}
            disabled={submitting || cart.length > 0}
            className={`rounded-xl py-3 text-sm font-bold disabled:opacity-50 ${
              type === t ? "text-white" : "border border-slate-200 text-slate-500"
            }`}
            style={type === t ? { backgroundColor: BRAND.deepGreen } : {}}
          >
            {t}
          </button>
        ))}
      </div>
      {cart.length > 0 && (
        <p className="mt-1.5 text-[11px] text-slate-400">장바구니에 항목이 있는 동안은 입고/출고 구분을 바꿀 수 없습니다.</p>
      )}

      {/* 공통 정보 — 차량 한 대 단위로 한 번만 입력 */}
      <div className="mt-5 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
        <p className="text-xs font-bold text-slate-500">공통 정보 (이 차량/요청 전체에 적용)</p>
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="text-xs font-semibold text-slate-500">차량번호</label>
            <input
              value={vehicleNo}
              onChange={(e) => setVehicleNo(e.target.value)}
              disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 focus:outline-none disabled:opacity-50"
            />
          </div>
          <div>
            <label className="text-xs font-semibold text-slate-500">출고요청자</label>
            <input
              value={requester}
              onChange={(e) => setRequester(e.target.value)}
              placeholder="요청자명부의 이름"
              disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
            />
          </div>
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">임시 L/C 사용여부</label>
          <div className="mt-1.5 grid grid-cols-2 gap-2">
            {[{ v: false, label: "사용 안함" }, { v: true, label: "사용함" }].map((opt) => (
              <button
                key={String(opt.v)}
                type="button"
                onClick={() => setTempLcUsed(opt.v)}
                disabled={submitting}
                className={`rounded-lg py-2 text-sm font-bold disabled:opacity-50 ${
                  tempLcUsed === opt.v ? "text-white" : "border border-slate-200 text-slate-500"
                }`}
                style={tempLcUsed === opt.v ? { backgroundColor: BRAND.deepGreen } : {}}
              >
                {opt.label}
              </button>
            ))}
          </div>
          {tempLcUsed && (
            <input
              value={tempLc}
              onChange={(e) => setTempLc(e.target.value)}
              placeholder="임시 L/C 번호 입력"
              disabled={submitting}
              className="mt-2 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
            />
          )}
        </div>
      </div>

      {/* 한 줄(품목) 추가 폼 */}
      <form onSubmit={handleAddToCart} className="mt-4 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
        <p className="text-xs font-bold text-slate-500">품목 추가</p>
        <div>
          <label className="text-xs font-semibold text-slate-500">PART NO *</label>
          <div className="mt-1.5 flex items-center gap-2">
            <input
              value={partNo}
              onChange={(e) => setPartNo(e.target.value)}
              placeholder="바코드 스캔 또는 직접 입력"
              disabled={submitting}
              className="w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
            />
            <button
              type="button"
              onClick={() => setScannerOpen(true)}
              disabled={submitting}
              className="flex h-[42px] w-[42px] flex-shrink-0 items-center justify-center rounded-lg text-white disabled:opacity-50"
              style={{ backgroundColor: BRAND.deepGreen }}
              title="바코드 스캔"
            >
              <ScanLine className="h-5 w-5" />
            </button>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="text-xs font-semibold text-slate-500">{type} 수량 *</label>
            <input
              type="number"
              min="1"
              value={quantity}
              onChange={(e) => setQuantity(e.target.value)}
              placeholder="0"
              disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
            />
          </div>
          <div>
            <label className="text-xs font-semibold text-slate-500">파레트</label>
            <input
              value={pallet}
              onChange={(e) => setPallet(e.target.value)}
              disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 focus:outline-none disabled:opacity-50"
            />
          </div>
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">비고</label>
          <div className="mt-1.5 grid grid-cols-2 gap-2">
            {["폐기", "기타"].map((n) => (
              <button
                key={n}
                type="button"
                onClick={() => setNote(note === n ? "" : n)}
                disabled={submitting}
                className={`rounded-lg py-2 text-sm font-bold disabled:opacity-50 ${
                  note === n ? "text-white" : "border border-slate-200 text-slate-500"
                }`}
                style={note === n ? { backgroundColor: BRAND.deepGreen } : {}}
              >
                {n}
              </button>
            ))}
          </div>
          {note && (
            <input
              value={noteDetail}
              onChange={(e) => setNoteDetail(e.target.value)}
              placeholder={`${note} 상세 입력`}
              disabled={submitting}
              className="mt-2 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
            />
          )}
        </div>

        {lineError && <p className="text-xs font-semibold text-red-500">{lineError}</p>}

        <button
          type="submit"
          disabled={submitting}
          className="flex w-full items-center justify-center gap-1.5 rounded-xl border-2 border-dashed py-3 text-sm font-bold disabled:opacity-50"
          style={{ borderColor: BRAND.deepGreen, color: BRAND.deepGreen }}
        >
          <PlusCircle className="h-4 w-4" /> 장바구니에 추가
        </button>
      </form>

      {/* 장바구니 목록 */}
      {cart.length > 0 && (
        <div className="mt-4">
          <p className="text-xs font-bold text-slate-500">
            장바구니 ({cart.length}건 · 총 {totalQuantity}개)
          </p>
          <div className="mt-2 space-y-2">
            {cart.map((line) => (
              <div key={line.cartId} className="flex items-center justify-between rounded-lg border border-slate-200 bg-white px-3 py-2.5">
                <div>
                  <p className="text-sm font-bold text-slate-900">{line.partNo}</p>
                  <p className="text-[11px] text-slate-400">
                    {type} {line.quantity}개{line.pallet ? ` · 파레트 ${line.pallet}` : ""}{line.note ? ` · ${line.note}` : ""}
                  </p>
                </div>
                <button
                  type="button"
                  onClick={() => handleRemoveFromCart(line.cartId)}
                  disabled={submitting}
                  className="flex h-7 w-7 items-center justify-center rounded-full text-slate-400 disabled:opacity-50"
                >
                  <X className="h-4 w-4" />
                </button>
              </div>
            ))}
          </div>

          <button
            onClick={handleSubmitAll}
            disabled={submitting}
            className="mt-4 flex w-full items-center justify-center gap-2 rounded-xl py-3.5 text-sm font-bold text-white disabled:opacity-50"
            style={{ backgroundColor: BRAND.deepGreen }}
          >
            {submitting
              ? `등록중... (${submitProgress ? submitProgress.done : 0}/${submitProgress ? submitProgress.total : cart.length})`
              : `전체 등록 (${cart.length}건)`}
          </button>
        </div>
      )}

      {/* 제출 결과 요약 */}
      {lastSummary && (
        <div className="mt-5 rounded-xl border border-slate-200 bg-white p-4">
          <p className="text-xs font-bold text-slate-500">등록 결과</p>
          <p className="mt-1 text-sm font-bold" style={{ color: BRAND.deepGreen }}>
            성공 {lastSummary.succeeded.length}건
            {lastSummary.failed.length > 0 && <span className="text-red-500"> · 실패 {lastSummary.failed.length}건</span>}
          </p>

          {lastSummary.succeeded.length > 0 && (
            <div className="mt-3 space-y-1.5">
              {lastSummary.succeeded.map(({ line, result }) => (
                <div key={line.cartId} className="flex items-center justify-between text-xs">
                  <span className="text-slate-700">{result.name || result.partNo} · {type} {result.quantity}개</span>
                  <span className="text-slate-400">
                    재고 {result.beforeStock} → <span className="font-bold" style={{ color: BRAND.deepGreen }}>{result.afterStock}</span>
                  </span>
                </div>
              ))}
            </div>
          )}

          {lastSummary.failed.length > 0 && (
            <div className="mt-3 space-y-1.5 rounded-lg border border-red-100 bg-red-50 p-3">
              <p className="text-[11px] font-semibold text-red-600">아래 항목은 실패해서 장바구니에 다시 담겨 있습니다. 확인 후 재시도해주세요.</p>
              {lastSummary.failed.map(({ line, message }) => (
                <p key={line.cartId} className="text-xs text-red-600">{line.partNo}: {message}</p>
              ))}
            </div>
          )}
        </div>
      )}

      {scannerOpen && <BarcodeScannerModal onScan={handleScanResult} onClose={() => setScannerOpen(false)} />}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 창원 — 재고조회 화면. Part No.별 현재 재고를 검색/조회.
// ────────────────────────────────────────────────────────────────────────
function StockSummaryScreen({ onBack }) {
  const [items, setItems] = useState([]);
  const [query, setQuery] = useState("");
  const [status, setStatus] = useState("loading"); // loading | ready | error
  const [error, setError] = useState("");

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const data = await listStockSummary();
        if (!cancelled) {
          setItems(data);
          setStatus("ready");
        }
      } catch (err) {
        if (!cancelled) {
          setError(err.message || "재고 목록을 불러오지 못했습니다.");
          setStatus("error");
        }
      }
    })();
    return () => { cancelled = true; };
  }, []);

  const filtered = items.filter((it) => {
    if (!query.trim()) return true;
    const q = query.trim().toLowerCase();
    return String(it.partNo).toLowerCase().includes(q) || String(it.name || "").toLowerCase().includes(q);
  });

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">재고조회</h1>
      <p className="mt-1 text-sm text-slate-400">PART NO 또는 품명으로 현재 재고를 검색합니다.</p>

      <div className="mt-5 flex items-center gap-2 rounded-lg border border-slate-200 px-3 py-2.5">
        <Search className="h-4 w-4 text-slate-400" />
        <input
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="PART NO 또는 품명 검색"
          className="w-full text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none"
        />
      </div>

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-2">
          {filtered.length === 0 && (
            <p className="py-8 text-center text-xs text-slate-400">검색 결과가 없습니다.</p>
          )}
          {filtered.map((it) => {
            const negative = Number(it.stock) < 0;
            return (
              <div key={it.partNo} className="rounded-xl border border-slate-200 bg-white p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-bold text-slate-900">{it.partNo}{it.lc ? ` · ${it.lc}` : ""}</p>
                    <p className="text-xs text-slate-400">{it.name || "(품명 미등록)"}</p>
                  </div>
                  <div className="text-right">
                    <p className={`text-lg font-extrabold ${negative ? "text-red-500" : ""}`} style={!negative ? { color: BRAND.deepGreen } : {}}>
                      {it.stock}
                    </p>
                    <p className="text-[10px] text-slate-400">{it.lastUpdated}</p>
                  </div>
                </div>
                {negative && (
                  <p className="mt-1.5 flex items-center gap-1 text-[11px] font-semibold text-red-500">
                    <AlertTriangle className="h-3 w-3" /> 음수 재고 — 현장 확인 필요
                  </p>
                )}
              </div>
            );
          })}
        </div>
      )}
    </main>
  );
}

/**
 * 창원 — 월별 수불표. 월을 선택하면 PART NO별로
 * "전월재고 + 입고 - 출고 = 당월재고" 형태의 표를 보여준다. (9번 요청 대응)
 */
function MonthlyLedgerScreen({ onBack }) {
  const defaultMonth = (() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
  })();
  const [yearMonth, setYearMonth] = useState(defaultMonth);
  const [query, setQuery] = useState("");
  const [items, setItems] = useState([]);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");

  const reload = async (month) => {
    setStatus("loading");
    try {
      const data = await getMonthlyLedger(month);
      setItems(data.items);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "월별 수불표를 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  useEffect(() => { reload(yearMonth); }, []);

  const filtered = items.filter((it) => {
    if (!query.trim()) return true;
    const q = query.trim().toLowerCase();
    return String(it.partNo).toLowerCase().includes(q) || String(it.name || "").toLowerCase().includes(q);
  });

  const totals = filtered.reduce(
    (acc, it) => ({ inQty: acc.inQty + (Number(it.inQty) || 0), outQty: acc.outQty + (Number(it.outQty) || 0) }),
    { inQty: 0, outQty: 0 }
  );

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">월별 수불표</h1>
      <p className="mt-1 text-sm text-slate-400">PART NO별 전월재고 + 입고 - 출고 = 당월재고 현황입니다.</p>

      <div className="mt-4 flex items-center gap-2">
        <input type="month" value={yearMonth} onChange={(e) => setYearMonth(e.target.value)}
          className="rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none" />
        <button onClick={() => reload(yearMonth)} className="flex items-center gap-1 rounded-lg border border-slate-200 px-3 py-2 text-xs font-bold text-slate-600">
          <RefreshCw className="h-3.5 w-3.5" /> 조회
        </button>
      </div>

      <div className="mt-3 flex items-center gap-2 rounded-lg border border-slate-200 px-3 py-2.5">
        <Search className="h-4 w-4 text-slate-400" />
        <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="PART NO 또는 품명 검색"
          className="w-full text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none" />
      </div>

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <>
          <div className="mt-4 grid grid-cols-2 gap-2 text-center">
            <div className="rounded-xl border border-slate-200 bg-white p-3">
              <p className="text-[11px] text-slate-400">이번 달 입고 합계</p>
              <p className="mt-1 text-lg font-extrabold" style={{ color: BRAND.deepGreen }}>{totals.inQty.toLocaleString()}</p>
            </div>
            <div className="rounded-xl border border-slate-200 bg-white p-3">
              <p className="text-[11px] text-slate-400">이번 달 출고 합계</p>
              <p className="mt-1 text-lg font-extrabold text-slate-700">{totals.outQty.toLocaleString()}</p>
            </div>
          </div>

          <div className="mt-3 space-y-2">
            {filtered.length === 0 && <p className="py-8 text-center text-xs text-slate-400">해당 월에 표시할 자재가 없습니다.</p>}
            {filtered.map((it) => {
              const closingNegative = Number(it.closingStock) < 0;
              return (
                <div key={it.partNo} className="rounded-xl border border-slate-200 bg-white p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-bold text-slate-900">{it.partNo}{it.lc ? ` · ${it.lc}` : ""}</p>
                      <p className="text-xs text-slate-400">{it.name || "(품명 미등록)"}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-[10px] text-slate-400">당월재고</p>
                      <p className={`text-lg font-extrabold ${closingNegative ? "text-red-500" : ""}`} style={!closingNegative ? { color: BRAND.deepGreen } : {}}>
                        {it.closingStock}
                      </p>
                    </div>
                  </div>
                  <div className="mt-2 grid grid-cols-3 gap-2 rounded-lg bg-slate-50 p-2 text-center">
                    <div>
                      <p className="text-[10px] text-slate-400">전월재고</p>
                      <p className="text-xs font-bold text-slate-700">{it.openingStock}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-slate-400">입고</p>
                      <p className="text-xs font-bold" style={{ color: BRAND.deepGreen }}>+{it.inQty}</p>
                    </div>
                    <div>
                      <p className="text-[10px] text-slate-400">출고</p>
                      <p className="text-xs font-bold text-slate-700">-{it.outQty}</p>
                    </div>
                  </div>
                  {closingNegative && (
                    <p className="mt-1.5 flex items-center gap-1 text-[11px] font-semibold text-red-500">
                      <AlertTriangle className="h-3 w-3" /> 음수 재고 — 현장 확인 필요
                    </p>
                  )}
                </div>
              );
            })}
          </div>
        </>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 공용 — 도면 위 핀 보드.
//   mode="view"  : 좌표가 있으면 핀만 표시(읽기 전용). 위치찾기 화면에서 사용.
//   mode="pick"  : 도면을 클릭하면 그 지점에 핀을 찍고 onPick(coordinate, zoneLabel)을 호출.
//                  자재등록 화면에서 사용. 기존 핀을 다시 클릭하면 위치가 갱신된다.
//                  도면에 구역(zones)이 정의돼 있으면 옅은 색 사각형으로 표시되고,
//                  구역 안을 탭하면 그 구역의 라벨이 onPick의 두 번째 인자로 전달된다.
// 좌표 저장 형식은 "x.x,y.y" (도면 가로/세로 대비 %, 소수 첫째자리) 이며,
// 기존 백엔드(자재마스터 도면좌표 컬럼)가 단순 텍스트 컬럼이라 그대로 호환된다.
// ────────────────────────────────────────────────────────────────────────
function FloorPlanPinBoard({ floor, coordinate, mode = "view", onPick }) {
  const plan = FLOOR_PLANS[floor];
  const [imgError, setImgError] = useState(false);
  const [hoverZoneKey, setHoverZoneKey] = useState(null);

  if (!plan) {
    return (
      <div className="flex h-40 items-center justify-center rounded-xl border border-dashed border-slate-300 bg-slate-50 text-xs text-slate-400">
        층수를 먼저 선택해주세요.
      </div>
    );
  }

  const parsed = parseCoordinate(coordinate);
  const zones = plan.zones || [];

  const handleClick = (e) => {
    if (mode !== "pick") return;
    const rect = e.currentTarget.getBoundingClientRect();
    const xPct = Math.min(100, Math.max(0, ((e.clientX - rect.left) / rect.width) * 100));
    const yPct = Math.min(100, Math.max(0, ((e.clientY - rect.top) / rect.height) * 100));
    const zone = findZoneAtPoint(zones, xPct, yPct);
    onPick(`${xPct.toFixed(1)},${yPct.toFixed(1)}`, zone ? zone.label : null);
  };

  return (
    <div>
      <div
        onClick={handleClick}
        onMouseLeave={() => setHoverZoneKey(null)}
        className={`relative w-full overflow-hidden rounded-xl border border-slate-200 bg-slate-100 ${mode === "pick" ? "cursor-crosshair" : ""}`}
        style={{ aspectRatio: "4 / 3" }}
        title={mode === "pick" ? "도면을 클릭해 보관 위치를 지정하세요" : undefined}
      >
        {!imgError ? (
          <img
            src={plan.src}
            alt={plan.label}
            draggable={false}
            onError={() => setImgError(true)}
            className="absolute inset-0 h-full w-full select-none object-contain"
          />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center text-center text-xs text-slate-400">
            도면 이미지를 불러오지 못했습니다.<br />네트워크 상태를 확인해주세요.
          </div>
        )}

        {mode === "pick" && zones.map((zone) => (
          <div
            key={zone.key}
            onMouseEnter={() => setHoverZoneKey(zone.key)}
            className="absolute rounded-sm border-2 transition-colors"
            style={{
              left: `${zone.x1}%`,
              top: `${zone.y1}%`,
              width: `${zone.x2 - zone.x1}%`,
              height: `${zone.y2 - zone.y1}%`,
              borderColor: hoverZoneKey === zone.key ? BRAND.deepGreen : "transparent",
              backgroundColor: hoverZoneKey === zone.key ? "rgba(14,92,48,0.16)" : "transparent",
            }}
          />
        ))}

        {parsed && (
          <span
            className="absolute -translate-x-1/2 -translate-y-full"
            style={{ left: `${parsed.x}%`, top: `${parsed.y}%` }}
          >
            <MapPin className="h-7 w-7 drop-shadow-md" style={{ color: BRAND.deepGreen, fill: BRAND.lime }} strokeWidth={2} />
          </span>
        )}
      </div>
      <p className="mt-1.5 text-[11px] text-slate-400">{plan.label}{mode === "pick" ? " · 탭하여 보관 위치 지정" : ""}</p>

      {mode === "pick" && zones.length > 0 && (
        <div className="mt-2 flex flex-wrap gap-1.5">
          {zones.map((zone) => (
            <span
              key={zone.key}
              onMouseEnter={() => setHoverZoneKey(zone.key)}
              onMouseLeave={() => setHoverZoneKey(null)}
              className="rounded-full border border-slate-200 px-2 py-1 text-[10px] font-semibold text-slate-500"
            >
              {zone.label}
            </span>
          ))}
        </div>
      )}
    </div>
  );
}

/** 점(xPct,yPct)이 속한 구역을 찾는다. 겹치는 경우 먼저 정의된 구역을 우선한다. */
function findZoneAtPoint(zones, xPct, yPct) {
  return zones.find((z) => xPct >= z.x1 && xPct <= z.x2 && yPct >= z.y1 && yPct <= z.y2) || null;
}

/** "x.x,y.y" 형태의 좌표 문자열을 { x, y } 숫자 객체로 변환. 형식이 다르면 null. */
function parseCoordinate(coordinate) {
  if (!coordinate) return null;
  const match = String(coordinate).trim().match(/^(\d+(?:\.\d+)?),\s*(\d+(?:\.\d+)?)$/);
  if (!match) return null;
  const x = parseFloat(match[1]);
  const y = parseFloat(match[2]);
  if (Number.isNaN(x) || Number.isNaN(y)) return null;
  return { x, y };
}

// ────────────────────────────────────────────────────────────────────────
// 창원 — 위치찾기 화면. PART NO로 층수를 조회한 뒤, 해당 층 도면 위에
// 실제 핀을 표시한다. 좌표 형식이 옛 데이터(예: "x120,y340")처럼 비율(%)이 아닌
// 경우는 핀 없이 좌표 텍스트만 보여준다(과거 AppSheet 데이터 호환).
// ────────────────────────────────────────────────────────────────────────
function MaterialLocationScreen({ onBack }) {
  const [partNo, setPartNo] = useState("");
  const [result, setResult] = useState(null);
  const [status, setStatus] = useState("idle"); // idle | loading | error
  const [error, setError] = useState("");

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!partNo.trim()) {
      setError("PART NO를 입력해주세요.");
      return;
    }
    setError("");
    setStatus("loading");
    setResult(null);
    try {
      const data = await findMaterialLocation(partNo.trim());
      setResult(data);
      setStatus("idle");
    } catch (err) {
      setError(err.message || "위치를 찾지 못했습니다.");
      setStatus("error");
    }
  };

  const hasFloorPlan = result && FLOOR_PLANS[result.floor];
  const pinParsed = result && parseCoordinate(result.coordinate);
  const pinZone = pinParsed && hasFloorPlan ? findZoneAtPoint(FLOOR_PLANS[result.floor].zones || [], pinParsed.x, pinParsed.y) : null;

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">위치찾기</h1>
      <p className="mt-1 text-sm text-slate-400">PART NO로 보관 층수와 도면 위 위치를 확인합니다.</p>

      <form onSubmit={handleSearch} className="mt-5 flex items-center gap-2 rounded-lg border border-slate-200 px-3 py-2.5">
        <Search className="h-4 w-4 text-slate-400" />
        <input
          value={partNo}
          onChange={(e) => setPartNo(e.target.value)}
          placeholder="PART NO 입력"
          className="w-full text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none"
        />
        <button type="submit" className="rounded-md px-3 py-1.5 text-xs font-bold text-white" style={{ backgroundColor: BRAND.deepGreen }}>
          조회
        </button>
      </form>

      {status === "error" && <p className="mt-4 text-xs font-semibold text-red-500">{error}</p>}

      {result && (
        <div className="mt-5 rounded-2xl border border-slate-200 bg-white p-5">
          <p className="text-sm font-bold text-slate-900">{result.name}</p>
          <p className="text-xs text-slate-400">{result.partNo}</p>

          <div className="mt-4 flex items-center gap-3 rounded-xl p-4" style={{ backgroundColor: BRAND.greenSoft }}>
            <span className="flex h-11 w-11 items-center justify-center rounded-xl bg-white">
              <MapPin className="h-5 w-5" style={{ color: BRAND.deepGreen }} />
            </span>
            <div>
              <p className="text-xs text-slate-500">보관 위치</p>
              <p className="text-base font-bold text-slate-900">{result.floor || "층수 미등록"}</p>
              {pinZone && <p className="text-[11px] font-semibold" style={{ color: BRAND.deepGreen }}>{pinZone.label}</p>}
            </div>
          </div>

          {hasFloorPlan ? (
            <div className="mt-3">
              <FloorPlanPinBoard floor={result.floor} coordinate={result.coordinate} mode="view" />
              {!pinParsed && result.coordinate && (
                <p className="mt-2 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-[11px] text-amber-700">
                  저장된 좌표({result.coordinate})가 예전 형식이라 도면 위에 핀으로 표시할 수 없습니다. 자재등록 화면에서 위치를 다시 지정해주세요.
                </p>
              )}
            </div>
          ) : (
            <div className="mt-3 rounded-xl border border-slate-100 bg-slate-50 p-3">
              <p className="text-[11px] font-semibold text-slate-500">도면좌표</p>
              <p className="mt-1 font-mono text-sm text-slate-800">{result.coordinate || "좌표 미등록"}</p>
              <p className="mt-2 text-[11px] text-slate-400">등록된 층수에 대한 도면 이미지를 찾을 수 없습니다.</p>
            </div>
          )}
        </div>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 창원 — 임시 L/C 재배치 화면. 임시 L/C를 사용중인 입출고내역만 모아서 보여준다.
// ────────────────────────────────────────────────────────────────────────
function TempLcScreen({ onBack }) {
  const [items, setItems] = useState([]);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const data = await listTempLcItems();
        if (!cancelled) { setItems(data); setStatus("ready"); }
      } catch (err) {
        if (!cancelled) { setError(err.message || "목록을 불러오지 못했습니다."); setStatus("error"); }
      }
    })();
    return () => { cancelled = true; };
  }, []);

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">임시 L/C 재배치</h1>
      <p className="mt-1 text-sm text-slate-400">임시 L/C를 사용중인 입출고내역만 모아서 보여줍니다.</p>

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-2">
          {items.length === 0 && (
            <p className="py-8 text-center text-xs text-slate-400">현재 임시 L/C 사용중인 항목이 없습니다.</p>
          )}
          {items.map((it) => (
            <div key={it.id} className="rounded-xl border border-amber-200 bg-amber-50 p-4">
              <div className="flex items-center justify-between">
                <p className="text-sm font-bold text-slate-900">{it.partNo}</p>
                <span className="rounded-full bg-amber-500 px-2 py-0.5 text-[10px] font-bold text-white">{it.type}</span>
              </div>
              <p className="mt-1 text-xs text-slate-500">{it.date} · {it.businessUnit || "사업부 미확인"}</p>
              <p className="mt-1.5 text-xs font-semibold text-amber-700">임시 L/C: {it.tempLc || "미입력"}</p>
            </div>
          ))}
        </div>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 창원 — 자재등록 화면(관리자 전용). 신규 PART NO를 자재마스터에 등록한다.
// 보관 층수를 고르면 그 층 도면이 뜨고, 도면을 탭하면 그 지점에 핀이 찍히며
// 좌표(x%,y%)가 자동으로 채워진다. AppSheet의 "위치찾기 핀 찍기" 워크플로우를
// 그대로 옮겨온 것 — 직접 좌표 숫자를 입력할 필요가 없다.
// ────────────────────────────────────────────────────────────────────────
function MaterialRegisterScreen({ employee, onBack }) {
  const [partNo, setPartNo] = useState("");
  const [name, setName] = useState("");
  const [lc, setLc] = useState("");
  const [businessUnit, setBusinessUnit] = useState("");
  const [floor, setFloor] = useState("1층");
  const [coordinate, setCoordinate] = useState("");
  const [zoneLabel, setZoneLabel] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(null);

  // 층수를 바꾸면 이전 층 도면에 찍었던 핀은 의미가 없으므로 좌표를 초기화한다.
  const handleFloorChange = (f) => {
    setFloor(f);
    setCoordinate("");
    setZoneLabel(null);
  };

  const handlePick = (coord, zone) => {
    setCoordinate(coord);
    setZoneLabel(zone);
  };

  const handleClearPin = () => {
    setCoordinate("");
    setZoneLabel(null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!partNo.trim()) {
      setError("PART NO를 입력해주세요.");
      return;
    }
    setError("");
    setSuccess(null);
    setSubmitting(true);
    try {
      const result = await registerMaterial(employee.employeeId, {
        partNo: partNo.trim(),
        name,
        lc,
        businessUnit,
        floor,
        coordinate,
        author: employee.name,
      });
      setSuccess(result.partNo);
      setPartNo(""); setName(""); setLc(""); setBusinessUnit(""); setCoordinate(""); setZoneLabel(null);
    } catch (err) {
      setError(err.message || "등록 중 오류가 발생했습니다.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">자재등록</h1>
      <p className="mt-1 text-sm text-slate-400">신규 PART NO를 자재마스터(창원)에 등록합니다.</p>

      <form onSubmit={handleSubmit} className="mt-5 space-y-4">
        <div>
          <label className="text-xs font-semibold text-slate-500">PART NO *</label>
          <input value={partNo} onChange={(e) => setPartNo(e.target.value)} disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">품명</label>
          <input value={name} onChange={(e) => setName(e.target.value)} disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="text-xs font-semibold text-slate-500">L/C</label>
            <input value={lc} onChange={(e) => setLc(e.target.value)} disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
          </div>
          <div>
            <label className="text-xs font-semibold text-slate-500">사업부</label>
            <input value={businessUnit} onChange={(e) => setBusinessUnit(e.target.value)} disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
          </div>
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">보관 층수 *</label>
          <div className="mt-1.5 grid grid-cols-4 gap-2">
            {FLOOR_OPTIONS.map((f) => (
              <button key={f} type="button" onClick={() => handleFloorChange(f)} disabled={submitting}
                className={`rounded-lg py-2 text-xs font-bold ${floor === f ? "text-white" : "border border-slate-200 text-slate-500"}`}
                style={floor === f ? { backgroundColor: BRAND.deepGreen } : {}}>
                {f}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className="text-xs font-semibold text-slate-500">보관 위치 지정 *</label>
          <div className="mt-1.5">
            <FloorPlanPinBoard floor={floor} coordinate={coordinate} mode="pick" onPick={handlePick} />
          </div>
          <div className="mt-2 flex items-center justify-between">
            <div>
              {zoneLabel && (
                <p className="text-[11px] font-bold" style={{ color: BRAND.deepGreen }}>{zoneLabel}</p>
              )}
              <p className="font-mono text-[11px] text-slate-500">
                {coordinate ? `좌표 (${coordinate})` : "아직 위치가 지정되지 않았습니다"}
              </p>
            </div>
            {coordinate && (
              <button type="button" onClick={handleClearPin} disabled={submitting}
                className="flex items-center gap-1 text-[11px] font-semibold text-slate-400">
                <X className="h-3 w-3" /> 핀 지우기
              </button>
            )}
          </div>
        </div>

        {error && <p className="text-xs font-semibold text-red-500">{error}</p>}
        {success && <p className="text-xs font-semibold" style={{ color: BRAND.deepGreen }}>{success} 등록 완료</p>}

        <button type="submit" disabled={submitting}
          className="flex w-full items-center justify-center gap-2 rounded-xl py-3.5 text-sm font-bold text-white disabled:opacity-50"
          style={{ backgroundColor: BRAND.deepGreen }}>
          {submitting ? "등록중..." : "자재 등록"}
        </button>
      </form>
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 창원 — 요청자명부 화면(관리자 전용 등록 + 누구나 조회).
// ────────────────────────────────────────────────────────────────────────
function RequesterScreen({ employee, onBack }) {
  const isAdmin = isElevatedRole(employee.role); // 관리자 또는 지원(15번)
  const [requesters, setRequesters] = useState([]);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");

  const [showForm, setShowForm] = useState(false);
  const [name, setName] = useState("");
  const [department, setDepartment] = useState("");
  const [contact, setContact] = useState("");
  const [owner, setOwner] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [formError, setFormError] = useState("");

  const reload = async () => {
    setStatus("loading");
    try {
      const data = await listRequesters();
      setRequesters(data);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "목록을 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  useEffect(() => { reload(); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!name.trim()) {
      setFormError("요청자명을 입력해주세요.");
      return;
    }
    setFormError("");
    setSubmitting(true);
    try {
      await registerRequester(employee.employeeId, { requesterName: name.trim(), department, contact, owner });
      setName(""); setDepartment(""); setContact(""); setOwner("");
      setShowForm(false);
      await reload();
    } catch (err) {
      setFormError(err.message || "등록 중 오류가 발생했습니다.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-bold text-slate-900">요청자명부</h1>
        {isAdmin && (
          <button onClick={() => setShowForm((v) => !v)}
            className="flex items-center gap-1 rounded-full px-3 py-1.5 text-xs font-bold text-white"
            style={{ backgroundColor: BRAND.deepGreen }}>
            <PlusCircle className="h-3.5 w-3.5" /> 등록
          </button>
        )}
      </div>
      <p className="mt-1 text-sm text-slate-400">LG전자 측 출고요청자 명부입니다.</p>

      {showForm && (
        <form onSubmit={handleSubmit} className="mt-4 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
          <div>
            <label className="text-xs font-semibold text-slate-500">요청자명 *</label>
            <input value={name} onChange={(e) => setName(e.target.value)} disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
          </div>
          <div className="grid grid-cols-2 gap-2">
            <div>
              <label className="text-xs font-semibold text-slate-500">소속부서</label>
              <input value={department} onChange={(e) => setDepartment(e.target.value)} disabled={submitting}
                className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
            </div>
            <div>
              <label className="text-xs font-semibold text-slate-500">연락처</label>
              <input value={contact} onChange={(e) => setContact(e.target.value)} disabled={submitting}
                className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
            </div>
          </div>
          <div>
            <label className="text-xs font-semibold text-slate-500">담당</label>
            <input value={owner} onChange={(e) => setOwner(e.target.value)} disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
          </div>
          {formError && <p className="text-xs font-semibold text-red-500">{formError}</p>}
          <button type="submit" disabled={submitting}
            className="w-full rounded-lg py-2.5 text-sm font-bold text-white disabled:opacity-50"
            style={{ backgroundColor: BRAND.deepGreen }}>
            {submitting ? "등록중..." : "저장"}
          </button>
        </form>
      )}

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-2">
          {requesters.length === 0 && <p className="py-8 text-center text-xs text-slate-400">등록된 요청자가 없습니다.</p>}
          {requesters.map((r) => (
            <div key={r.id} className="rounded-xl border border-slate-200 bg-white p-4">
              <div className="flex items-center justify-between">
                <p className="text-sm font-bold text-slate-900">{r.name}</p>
                <span className="text-[11px] text-slate-400">사번 {r.id}</span>
              </div>
              <p className="mt-1 text-xs text-slate-500">{r.department || "부서 미입력"} · {r.contact || "연락처 미입력"}</p>
              {r.owner && <p className="mt-1 text-[11px] text-slate-400">담당: {r.owner}</p>}
            </div>
          ))}
        </div>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 창원(마산) 홈화면 — 메뉴 카드에서 각 세부 화면으로 이동한다.
// ────────────────────────────────────────────────────────────────────────
/**
 * 창원(마산) "요청" 등록 화면(17번 요청) — "3층 담당자, 1층 지원 바람." 같은
 * 자연어 요청을 그대로 등록한다. 등록되면 알림 목록에 빨간색으로 표시된다.
 */
function ChangwonRequestScreen({ employee, onBack }) {
  const [message, setMessage] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [done, setDone] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!message.trim()) {
      setError("요청 내용을 입력해주세요.");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      await registerChangwonRequest(employee.employeeId, message.trim());
      setDone(true);
    } catch (err) {
      setError(err.message || "요청 등록 중 오류가 발생했습니다.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">요청</h1>
      <p className="mt-1 text-sm text-slate-400">
        자유롭게 적어주시면 전체 알림에 빨간색으로 표시됩니다.
      </p>

      {done ? (
        <div className="mt-6 rounded-xl border border-slate-200 bg-white p-4 text-center">
          <p className="text-sm font-bold" style={{ color: BRAND.deepGreen }}>요청이 등록되었습니다.</p>
          <button onClick={() => { setDone(false); setMessage(""); }} className="mt-3 text-xs font-semibold text-slate-400 underline">
            새 요청 등록하기
          </button>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="mt-5 space-y-3">
          <textarea
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            rows={5}
            placeholder="요청 내용을 입력해주세요"
            disabled={submitting}
            className="w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
          />
          {error && <p className="text-xs font-semibold text-red-500">{error}</p>}
          <button type="submit" disabled={submitting} className="w-full rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: "#dc2626" }}>
            {submitting ? "등록중..." : "요청 등록"}
          </button>
        </form>
      )}
    </main>
  );
}

