// ────────────────────────────────────────────────────────────────────────
// 공통 — 직원명부 조회 화면(관리자 전용). 창원/김해 양쪽 홈에서 진입 가능.
// ────────────────────────────────────────────────────────────────────────
// 직책 정렬 순서. 목록에 없는 직책("사원", 빈칸, 그 외 모든 값)은
// 맨 마지막 한 그룹으로 취급해 같은 우선순위로 묶인다.
const TITLE_ORDER = ["대표이사", "부사장", "감사", "상무", "실장", "부장", "차장", "과장", "계장", "대리", "조장"];
function titleRank(title) {
  const idx = TITLE_ORDER.indexOf(String(title || "").trim());
  return idx === -1 ? TITLE_ORDER.length : idx;
}

// 소속 정렬 순서 — 창원(마산)공장을 먼저, 김해공장을 다음으로 묶어서 보여준다.
// (같은 직책이어도 소속이 섞여 있으면 보기 어렵다는 12번 현장 피드백 대응)
const SITE_ORDER = ["changwon", "gimhae"];
function siteRank(homeSite) {
  const idx = SITE_ORDER.indexOf(homeSite);
  return idx === -1 ? SITE_ORDER.length : idx;
}

function EmployeeListScreen({ employee, onBack }) {
  const [employees, setEmployees] = useState([]);
  const [query, setQuery] = useState("");
  const [siteFilter, setSiteFilter] = useState("all"); // all | changwon | gimhae
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const data = await listEmployees(employee.employeeId);
        if (!cancelled) { setEmployees(data); setStatus("ready"); }
      } catch (err) {
        if (!cancelled) { setError(err.message || "직원명부를 불러오지 못했습니다."); setStatus("error"); }
      }
    })();
    return () => { cancelled = true; };
  }, [employee.employeeId]);

  const filtered = employees
    .filter((e) => {
      if (siteFilter !== "all" && e.homeSite !== siteFilter) return false;
      if (!query.trim()) return true;
      const q = query.trim().toLowerCase();
      return String(e.name).toLowerCase().includes(q) || String(e.employeeId).toLowerCase().includes(q) || String(e.department || "").toLowerCase().includes(q);
    })
    .sort((a, b) => titleRank(a.title) - titleRank(b.title) || siteRank(a.homeSite) - siteRank(b.homeSite) || String(a.name).localeCompare(String(b.name), "ko"));

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">직원명부</h1>
      <p className="mt-1 text-sm text-slate-400">전체 직원 목록(관리자 전용)입니다.</p>

      <div className="mt-5 flex items-center gap-2 rounded-lg border border-slate-200 px-3 py-2.5">
        <Search className="h-4 w-4 text-slate-400" />
        <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="이름, 사번, 부서 검색"
          className="w-full text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none" />
      </div>

      <div className="mt-3 grid grid-cols-3 gap-2">
        {[{ v: "all", label: "전체" }, { v: "changwon", label: "창원" }, { v: "gimhae", label: "김해" }].map((opt) => (
          <button key={opt.v} onClick={() => setSiteFilter(opt.v)}
            className={`rounded-lg py-2 text-xs font-bold ${siteFilter === opt.v ? "text-white" : "border border-slate-200 text-slate-500"}`}
            style={siteFilter === opt.v ? { backgroundColor: BRAND.deepGreen } : {}}>
            {opt.label}
          </button>
        ))}
      </div>

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-2">
          {filtered.length === 0 && <p className="py-8 text-center text-xs text-slate-400">검색 결과가 없습니다.</p>}
          {filtered.map((e) => (
            <div key={e.employeeId} className="rounded-xl border border-slate-200 bg-white p-4">
              <div className="flex items-center justify-between">
                <p className="text-sm font-bold text-slate-900">{e.name} <span className="text-xs font-normal text-slate-400">{e.title}</span></p>
                <span className="rounded-full px-2 py-0.5 text-[10px] font-bold text-white" style={{ backgroundColor: ROLE_BADGE_COLORS[e.role] || BRAND.deepGreen }}>
                  {ROLE_LABELS[e.role] || e.role}
                </span>
              </div>
              <p className="mt-1 text-xs text-slate-500">{e.employeeId} · {SITES[e.homeSite]?.label || e.homeSite} · {e.department}</p>
              <div className="mt-1 flex items-center justify-between gap-2">
                <p className="text-[11px] text-slate-400">{e.contact || "연락처 미입력"} {e.email ? `· ${e.email}` : ""}</p>
                {e.contact && (
                  <a href={`tel:${e.contact}`} className="flex flex-shrink-0 items-center gap-1 rounded-full px-2.5 py-1 text-[11px] font-bold text-white" style={{ backgroundColor: BRAND.deepGreen }}>
                    <Phone className="h-3 w-3" /> 전화
                  </a>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 공용 — 현장 사진 촬영/첨부. 모바일에서는 capture="environment"로 후면
// 카메라가 바로 열리고, PC에서는 일반 파일 선택창이 뜬다. 선택된 이미지는
// 캔버스로 리사이즈(최대 1280px)해 JPEG로 압축한 뒤 data URL로 보관한다
// (그대로 보내면 수 MB가 될 수 있어, 업로드 전에 가볍게 만들어둔다).
// ────────────────────────────────────────────────────────────────────────
function PhotoCapture({ value, onChange }) {
  const inputRef = useRef(null);
  const [processing, setProcessing] = useState(false);

  const handleFile = (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    setProcessing(true);

    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const maxDim = 1280;
        const scale = Math.min(1, maxDim / Math.max(img.width, img.height));
        const canvas = document.createElement("canvas");
        canvas.width = img.width * scale;
        canvas.height = img.height * scale;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        onChange(canvas.toDataURL("image/jpeg", 0.8));
        setProcessing(false);
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  };

  return (
    <div>
      <input ref={inputRef} type="file" accept="image/*" capture="environment" onChange={handleFile} className="hidden" />
      {value ? (
        <div className="relative overflow-hidden rounded-xl border border-slate-200">
          <img src={value} alt="현장 사진" className="h-40 w-full object-cover" />
          <button
            type="button"
            onClick={() => onChange(null)}
            className="absolute right-2 top-2 flex h-7 w-7 items-center justify-center rounded-full bg-black/55 text-white"
          >
            <X className="h-4 w-4" />
          </button>
        </div>
      ) : (
        <button
          type="button"
          onClick={() => inputRef.current && inputRef.current.click()}
          disabled={processing}
          className="flex h-32 w-full flex-col items-center justify-center gap-1.5 rounded-xl border-2 border-dashed border-slate-300 text-slate-400 disabled:opacity-50"
        >
          {processing ? <Loader2 className="h-6 w-6 animate-spin" /> : <Camera className="h-6 w-6" />}
          <span className="text-xs font-semibold">{processing ? "처리중..." : "현장 사진 촬영/첨부"}</span>
        </button>
      )}
    </div>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 공용 — 인수자 서명 캡처. 손가락/마우스로 캔버스에 그린 선을 그대로
// data URL(PNG)로 변환해 onChange에 넘긴다. "지우기"로 다시 그릴 수 있다.
// ────────────────────────────────────────────────────────────────────────
function SignaturePad({ onChange }) {
  const canvasRef = useRef(null);
  const drawingRef = useRef(false);
  const [hasSignature, setHasSignature] = useState(false);

  // 캔버스의 "내부 해상도"(width/height 속성, 400x150)와 "화면에 보이는 크기"(CSS
  // w-full/h-32)가 서로 다르기 때문에, 터치/클릭 좌표(화면 기준)를 그대로 캔버스에
  // 그리면 위치가 어긋나거나 서명이 비뚤어지는 문제가 있었다(20번 오류). 화면 크기
  // 대비 내부 해상도의 비율(scaleX/scaleY)을 곱해 보정한다.
  const getPos = (canvas, e) => {
    const rect = canvas.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (clientX - rect.left) * scaleX, y: (clientY - rect.top) * scaleY };
  };

  const start = (e) => {
    e.preventDefault();
    drawingRef.current = true;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const { x, y } = getPos(canvas, e);
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const move = (e) => {
    if (!drawingRef.current) return;
    e.preventDefault();
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const { x, y } = getPos(canvas, e);
    ctx.lineWidth = 2.5;
    ctx.lineCap = "round";
    ctx.strokeStyle = "#1C2620";
    ctx.lineTo(x, y);
    ctx.stroke();
    if (!hasSignature) setHasSignature(true);
  };

  const end = () => {
    if (!drawingRef.current) return;
    drawingRef.current = false;
    const canvas = canvasRef.current;
    onChange(canvas.toDataURL("image/png"));
  };

  const handleClear = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    setHasSignature(false);
    onChange(null);
  };

  return (
    <div>
      <canvas
        ref={canvasRef}
        width={400}
        height={150}
        onMouseDown={start}
        onMouseMove={move}
        onMouseUp={end}
        onMouseLeave={end}
        onTouchStart={start}
        onTouchMove={move}
        onTouchEnd={end}
        className="h-32 w-full touch-none rounded-xl border border-slate-200 bg-white"
      />
      <div className="mt-1.5 flex items-center justify-between">
        <p className="text-[11px] text-slate-400">인수자가 위 칸에 직접 서명해주세요</p>
        {hasSignature && (
          <button type="button" onClick={handleClear} className="flex items-center gap-1 text-[11px] font-semibold text-slate-400">
            <X className="h-3 w-3" /> 지우기
          </button>
        )}
      </div>
    </div>
  );
}


// ────────────────────────────────────────────────────────────────────────
// 김해 — 완료 보고 제출 모달. "현장 사진 첨부 + 인수자 서명 완료"(PRD 7번)를
// 실제로 구현한 화면. 모달이 열리는 순간 실제 GPS로 현재 위치를 측정해
// 거래처 좌표와의 거리를 계산하고, 반경(GEOFENCE_RADIUS_METERS) 밖이면
// 경고를 보여준다 — 시뮬레이션 토글 대신 진짜 위치 기반으로 동작한다.
// 거래처에 좌표가 없으면(지오코딩 실패 등) 지오펜싱 검사 없이 진행한다.
// ────────────────────────────────────────────────────────────────────────
function CompletionReportModal({ item, customer, onClose, onSubmit }) {
  const [photo, setPhoto] = useState(null);
  const [signature, setSignature] = useState(null);
  const [signerName, setSignerName] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const [gpsStatus, setGpsStatus] = useState("locating"); // locating | ok | unavailable
  const [gpsPos, setGpsPos] = useState(null);
  const [distance, setDistance] = useState(null);
  const [forceSubmit, setForceSubmit] = useState(false);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const pos = await getCurrentPosition();
      if (cancelled) return;
      if (pos.error) {
        setGpsStatus("unavailable");
        return;
      }
      setGpsPos(pos);
      setGpsStatus("ok");
      if (customer && customer.latitude != null && customer.longitude != null) {
        const d = distanceInMeters(pos.lat, pos.lng, Number(customer.latitude), Number(customer.longitude));
        setDistance(d);
      }
    })();
    return () => { cancelled = true; };
  }, [customer]);

  const outOfFence = distance != null && distance > GEOFENCE_RADIUS_METERS;

  const handleSubmit = async () => {
    if (outOfFence && !forceSubmit) {
      setError("목적지 반경을 벗어난 상태입니다. 그래도 제출하려면 아래 확인란을 체크해주세요.");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      await onSubmit({
        photoBase64: photo,
        signatureBase64: signature,
        signerName,
        completedLat: gpsPos ? gpsPos.lat : null,
        completedLng: gpsPos ? gpsPos.lng : null,
      });
    } catch (err) {
      setError(err.message || "제출 중 오류가 발생했습니다.");
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/40 sm:items-center">
      <div className="max-h-[92vh] w-full max-w-sm overflow-y-auto rounded-t-2xl bg-white p-5 sm:rounded-2xl">
        <div className="flex items-center justify-between">
          <h2 className="text-base font-bold text-slate-900">완료 보고 제출</h2>
          <button onClick={onClose} className="text-slate-400"><X className="h-5 w-5" /></button>
        </div>
        <p className="mt-0.5 text-xs text-slate-400">{item.customerName} · {item.taskDescription}</p>

        {/* GPS 지오펜싱 상태 표시 */}
        <div className={`mt-4 flex items-start gap-2.5 rounded-xl p-3 ${outOfFence ? "bg-amber-50" : "bg-slate-50"}`}>
          {gpsStatus === "locating" ? (
            <Loader2 className="mt-0.5 h-4 w-4 animate-spin text-slate-400" />
          ) : (
            <Crosshair className="mt-0.5 h-4 w-4" style={{ color: outOfFence ? "#d97706" : BRAND.deepGreen }} />
          )}
          <div className="text-xs">
            {gpsStatus === "locating" && <p className="text-slate-500">현재 위치를 확인하는 중...</p>}
            {gpsStatus === "unavailable" && <p className="text-slate-500">위치 확인이 불가능합니다(권한 거부 또는 미지원). 지오펜싱 검사 없이 제출됩니다.</p>}
            {gpsStatus === "ok" && distance == null && <p className="text-slate-500">위치 확인됨. 이 거래처는 좌표가 등록되지 않아 거리 비교를 할 수 없습니다.</p>}
            {gpsStatus === "ok" && distance != null && (
              <p className={outOfFence ? "font-semibold text-amber-700" : "text-slate-600"}>
                목적지와의 거리: 약 {Math.round(distance)}m
                {outOfFence ? ` — 반경 ${GEOFENCE_RADIUS_METERS}m를 벗어났습니다` : " (반경 안)"}
              </p>
            )}
          </div>
        </div>

        <div className="mt-4">
          <label className="text-xs font-semibold text-slate-500">현장 사진</label>
          <div className="mt-1.5">
            <PhotoCapture value={photo} onChange={setPhoto} />
          </div>
        </div>

        <div className="mt-4">
          <label className="text-xs font-semibold text-slate-500">인수자 이름</label>
          <input
            value={signerName}
            onChange={(e) => setSignerName(e.target.value)}
            placeholder="예: 김철수"
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none"
          />
        </div>

        <div className="mt-4">
          <label className="text-xs font-semibold text-slate-500">인수자 서명</label>
          <div className="mt-1.5">
            <SignaturePad onChange={setSignature} />
          </div>
        </div>

        {outOfFence && (
          <label className="mt-4 flex items-start gap-2 rounded-lg border border-amber-200 bg-amber-50 p-3 text-xs text-amber-700">
            <input type="checkbox" checked={forceSubmit} onChange={(e) => setForceSubmit(e.target.checked)} className="mt-0.5" />
            반경을 벗어난 상태이지만 실제로 현장에서 작업을 완료했습니다.
          </label>
        )}

        {error && <p className="mt-3 text-xs font-semibold text-red-500">{error}</p>}

        <button
          onClick={handleSubmit}
          disabled={submitting || gpsStatus === "locating"}
          className="mt-5 flex w-full items-center justify-center gap-2 rounded-xl py-3.5 text-sm font-bold text-white disabled:opacity-50"
          style={{ backgroundColor: BRAND.deepGreen }}
        >
          {submitting ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle2 className="h-4 w-4" />}
          {submitting ? "제출중..." : "완료 보고 제출"}
        </button>
      </div>
    </div>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 김해 — 스마트 동선 최적화 (9차 업데이트, 관리자 전용).
//   1) 오늘 대기중인 거래처를 체크박스로 선택(=합짐 제안과 동일한 "같은
//      차량에 실을 거래처 조합" 개념)
//   2) "최적 동선 분석하기" → 선택한 순서(원래 체크 순서) vs 카카오 AI
//      추천 순서(Nearest Neighbor + 카카오 모빌리티 길찾기 API)를 비교
//   3) 절감된 거리/시간/예상 유류비를 보여주고, "기사 앱으로 전송"(=오늘일정
//      목록의 표시 순서에 별도로 적용하는 건 다음 단계 과제이며, 지금은
//      추천 순서를 사용자가 직접 참고해 진행하는 형태)
// 합짐 제안(가까운 거래처 묶음)도 같은 화면에서 함께 보여준다 — 둘 다 같은
// 거리 데이터를 기반으로 하는 한 묶음의 기능이기 때문이다.
// ────────────────────────────────────────────────────────────────────────
function GimhaeRouteOptimizerScreen({ employee, onBack }) {
  const [schedules, setSchedules] = useState([]);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");
  const [selectedIds, setSelectedIds] = useState([]); // 체크된 순서를 그대로 유지(=선택한 순서)
  const [analyzing, setAnalyzing] = useState(false);
  const [analyzeError, setAnalyzeError] = useState("");
  const [result, setResult] = useState(null);

  const [groups, setGroups] = useState([]);
  const [groupsStatus, setGroupsStatus] = useState("loading");

  const reload = async () => {
    setStatus("loading");
    try {
      const data = await listGimhaeSchedule();
      setSchedules(data.filter((s) => s.status !== "완료"));
      setStatus("ready");
    } catch (err) {
      setError(err.message || "오늘일정을 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  const loadGroups = async () => {
    setGroupsStatus("loading");
    try {
      const data = await suggestGimhaeGrouping(employee.employeeId);
      setGroups(data);
      setGroupsStatus("ready");
    } catch (err) {
      setGroupsStatus("error");
    }
  };

  useEffect(() => {
    reload();
    loadGroups();
  }, []);

  const toggleSelect = (customerId) => {
    setSelectedIds((prev) =>
      prev.includes(customerId) ? prev.filter((id) => id !== customerId) : [...prev, customerId]
    );
    setResult(null);
  };

  const handleAnalyze = async () => {
    if (selectedIds.length < 2) {
      setAnalyzeError("거래처를 2곳 이상 선택해주세요.");
      return;
    }
    setAnalyzeError("");
    setAnalyzing(true);
    setResult(null);
    try {
      // 출발지는 항상 "현재 위치(GPS)"를 먼저 시도한다 — 실제로 김해공장이 아니라
      // 직전 거래처 등 다른 곳에서 출발하는 경우가 많기 때문. GPS를 못 받으면(권한
      // 거부, PC 환경 등) 서버가 자동으로 김해공장 주소를 출발지로 대체해 계산한다.
      const position = await getCurrentPosition();
      const origin = position.error ? null : { lat: position.lat, lng: position.lng };
      const data = await optimizeGimhaeRoute(employee.employeeId, selectedIds, origin);
      setResult(data);
    } catch (err) {
      setAnalyzeError(err.message || "동선 분석 중 오류가 발생했습니다.");
    } finally {
      setAnalyzing(false);
    }
  };

  const handleReset = () => {
    setSelectedIds([]);
    setResult(null);
    setAnalyzeError("");
  };

  const fmtKm = (m) => (m / 1000).toFixed(1) + "km";
  const fmtMin = (s) => Math.round(s / 60) + "분";
  const fmtWon = (w) => Math.round(w).toLocaleString() + "원";

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <div className="flex items-center justify-between">
        <h1 className="flex items-center gap-1.5 text-xl font-bold text-slate-900">
          <Route className="h-5 w-5" style={{ color: BRAND.deepGreen }} /> 김해공장 스마트 동선 최적화
        </h1>
        <button onClick={handleReset} className="flex items-center gap-1 text-xs font-semibold text-slate-400">
          <RefreshCw className="h-3.5 w-3.5" /> 초기화
        </button>
      </div>
      <p className="mt-1 text-sm text-slate-400">그린산업(주) · 순회 납품 동선, 카카오모빌리티 경유지 최적화 연동</p>

      {/* 1) 거래처 선택 */}
      <div className="mt-5 rounded-2xl border border-slate-200 bg-white p-4">
        <p className="flex items-center gap-1.5 text-sm font-bold text-slate-900">
          <Layers className="h-4 w-4" /> 김해공장 순회 납품 동선
        </p>
        <p className="mt-0.5 text-[11px] text-slate-400">차량과 방문할 거래처를 선택하세요(체크 순서 = 현재 계획)</p>

        {status === "loading" && <p className="mt-4 text-center text-xs text-slate-400">불러오는 중...</p>}
        {status === "error" && <p className="mt-4 text-center text-xs font-semibold text-red-500">{error}</p>}

        {status === "ready" && (
          <div className="mt-3 space-y-2">
            {schedules.length === 0 && <p className="py-6 text-center text-xs text-slate-400">대기중인 일정이 없습니다.</p>}
            {schedules.map((item) => {
              const checked = selectedIds.includes(item.customerId);
              const order = selectedIds.indexOf(item.customerId);
              return (
                <button
                  key={item.dispatchId}
                  onClick={() => toggleSelect(item.customerId)}
                  className="flex w-full items-center gap-3 rounded-xl border border-slate-200 px-3 py-3 text-left active:bg-slate-50"
                >
                  <span
                    className="flex h-5 w-5 flex-shrink-0 items-center justify-center rounded-md border-2"
                    style={checked ? { backgroundColor: BRAND.deepGreen, borderColor: BRAND.deepGreen } : { borderColor: "#cbd5e1" }}
                  >
                    {checked && <CheckCircle2 className="h-3.5 w-3.5 text-white" />}
                  </span>
                  <span className="min-w-0 flex-1">
                    <p className="truncate text-sm font-bold text-slate-900">{item.customerName}</p>
                    <p className="truncate text-[11px] text-slate-400">{item.taskDescription}</p>
                  </span>
                  {checked && (
                    <span className="flex h-5 w-5 flex-shrink-0 items-center justify-center rounded-full text-[10px] font-bold text-white" style={{ backgroundColor: BRAND.deepGreen }}>
                      {order + 1}
                    </span>
                  )}
                </button>
              );
            })}
          </div>
        )}

        {analyzeError && <p className="mt-3 text-xs font-semibold text-red-500">{analyzeError}</p>}

        <button
          onClick={handleAnalyze}
          disabled={analyzing || selectedIds.length < 2}
          className="mt-4 flex w-full items-center justify-center gap-2 rounded-xl py-3.5 text-sm font-bold text-white disabled:opacity-40"
          style={{ backgroundColor: BRAND.deepGreen }}
        >
          {analyzing ? <Loader2 className="h-4 w-4 animate-spin" /> : <Route className="h-4 w-4" />}
          최적 동선 분석하기 ({selectedIds.length}곳)
        </button>
      </div>

      {/* 2) 방문 순서 비교 + 절감 효과 */}
      {result && (
        <div className="mt-4 rounded-2xl border border-slate-200 bg-white p-4">
          <p className="text-sm font-bold text-slate-900">방문 순서 비교</p>
          {result.origin?.name && (
            <p className="mt-0.5 flex items-center gap-1 text-[11px] text-slate-400">
              <Crosshair className="h-3 w-3" /> 출발지: {result.origin.name}
            </p>
          )}
          <div className="mt-3 grid grid-cols-2 gap-3">
            <div className="rounded-xl border border-slate-100 bg-slate-50 p-3">
              <p className="text-[11px] font-bold text-slate-500">최적화 전(선택한 순서)</p>
              <ol className="mt-2 space-y-1.5">
                {result.originalOrder.map((o, idx) => (
                  <li key={o.customerId} className="flex items-center gap-1.5 text-xs text-slate-600">
                    <span className="flex h-4 w-4 flex-shrink-0 items-center justify-center rounded-full bg-slate-300 text-[9px] font-bold text-white">{idx + 1}</span>
                    <span className="truncate">{o.customerName}</span>
                  </li>
                ))}
              </ol>
            </div>
            <div className="rounded-xl p-3" style={{ backgroundColor: BRAND.greenSoft }}>
              <p className="flex items-center gap-1 text-[11px] font-bold" style={{ color: BRAND.deepGreen }}>
                <TrendingDown className="h-3 w-3" /> 카카오 AI 추천 순서
              </p>
              <ol className="mt-2 space-y-1.5">
                {result.recommendedOrder.map((o, idx) => (
                  <li key={o.customerId} className="flex items-center gap-1.5 text-xs font-semibold text-slate-700">
                    <span className="flex h-4 w-4 flex-shrink-0 items-center justify-center rounded-full text-[9px] font-bold text-white" style={{ backgroundColor: BRAND.deepGreen }}>{idx + 1}</span>
                    <span className="truncate">{o.customerName}</span>
                  </li>
                ))}
              </ol>
            </div>
          </div>

          {result.saved && (
            <div className="mt-4">
              <div className="flex items-center justify-between">
                <p className="text-sm font-bold text-slate-900">최적화 절감 효과</p>
                {result.saved.distancePercent > 0 && (
                  <span className="flex items-center gap-1 rounded-full bg-emerald-50 px-2 py-0.5 text-[11px] font-bold text-emerald-600">
                    <TrendingDown className="h-3 w-3" /> 거리 {result.saved.distancePercent}% 절감
                  </span>
                )}
              </div>
              <div className="mt-2 grid grid-cols-3 gap-2">
                <div className="rounded-lg border border-slate-100 p-2.5 text-center">
                  <p className="text-[10px] text-slate-400">이동 거리</p>
                  <p className="text-[10px] text-slate-300 line-through">{fmtKm(result.originalRoute.distanceM)}</p>
                  <p className="text-sm font-extrabold text-slate-900">{fmtKm(result.recommendedRoute.distanceM)}</p>
                  <p className="text-[10px] font-semibold text-emerald-600">-{fmtKm(result.saved.distanceM)}</p>
                </div>
                <div className="rounded-lg border border-slate-100 p-2.5 text-center">
                  <p className="text-[10px] text-slate-400">이동 시간</p>
                  <p className="text-[10px] text-slate-300 line-through">{fmtMin(result.originalRoute.durationS)}</p>
                  <p className="text-sm font-extrabold text-slate-900">{fmtMin(result.recommendedRoute.durationS)}</p>
                  <p className="text-[10px] font-semibold text-emerald-600">-{fmtMin(result.saved.durationS)}</p>
                </div>
                <div className="rounded-lg border border-slate-100 p-2.5 text-center">
                  <p className="flex items-center justify-center gap-0.5 text-[10px] text-slate-400"><Fuel className="h-2.5 w-2.5" /> 예상 유류비</p>
                  <p className="text-[10px] text-slate-300 line-through">{fmtWon(result.originalRoute.fuelCostWon)}</p>
                  <p className="text-sm font-extrabold text-slate-900">{fmtWon(result.recommendedRoute.fuelCostWon)}</p>
                  <p className="text-[10px] font-semibold text-emerald-600">-{fmtWon(result.saved.fuelCostWon)}</p>
                </div>
              </div>
            </div>
          )}

          {result.skippedCustomers && result.skippedCustomers.length > 0 && (
            <p className="mt-3 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-[11px] text-amber-700">
              좌표가 없어 분석에서 제외된 거래처: {result.skippedCustomers.map((c) => c.customerName).join(", ")}
            </p>
          )}

          <button
            disabled
            title="다음 단계 과제 — 추천 순서를 오늘일정 표시 순서/기사 앱에 자동 반영하는 기능은 아직 준비중입니다"
            className="mt-4 flex w-full items-center justify-center gap-2 rounded-xl py-3 text-sm font-bold text-white opacity-50"
            style={{ backgroundColor: "#1e293b" }}
          >
            <Send className="h-4 w-4" /> 최적화된 동선을 기사 앱으로 전송 (준비중)
          </button>
        </div>
      )}

      {/* 3) 합짐 제안 */}
      <div className="mt-4 rounded-2xl border border-slate-200 bg-white p-4">
        <p className="text-sm font-bold text-slate-900">합짐 제안</p>
        <p className="mt-0.5 text-[11px] text-slate-400">거리가 가까운 거래처들을 한 차량에 같이 실을 수 있도록 묶어서 제안합니다.</p>

        {groupsStatus === "loading" && <p className="mt-3 text-center text-xs text-slate-400">분석중...</p>}
        {groupsStatus === "error" && <p className="mt-3 text-center text-xs text-slate-400">합짐 제안을 불러오지 못했습니다.</p>}
        {groupsStatus === "ready" && groups.length === 0 && (
          <p className="mt-3 text-center text-xs text-slate-400">지금 묶을 수 있는 가까운 거래처 조합이 없습니다.</p>
        )}
        {groupsStatus === "ready" && groups.length > 0 && (
          <div className="mt-3 space-y-2">
            {groups.map((group, idx) => (
              <div key={idx} className="rounded-xl border border-slate-100 bg-slate-50 p-3">
                <p className="text-[11px] font-bold text-slate-500">조합 {idx + 1} · {group.stopCount}곳</p>
                <p className="mt-1 text-xs text-slate-700">{group.stops.map((s) => s.customerName).join(" · ")}</p>
                <button
                  onClick={() => setSelectedIds(group.stops.map((s) => s.customerId))}
                  className="mt-2 text-[11px] font-bold"
                  style={{ color: BRAND.deepGreen }}
                >
                  이 조합으로 동선 분석하기 →
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 김해 — 오늘일정 화면. "제로 클릭 타임 트래킹" 구현부.
//   - "카카오내비로 길찾기" 버튼 클릭 → 출발시각 자동 기록(markGimhaeDeparted)
//   - "완료 보고 제출" 버튼 클릭 → CompletionReportModal을 열어 사진/서명/GPS
//     지오펜싱(실제 위치 기반)을 확인한 뒤 완료시각을 자동 기록한다.
// ────────────────────────────────────────────────────────────────────────
function GimhaeScheduleScreen({ employee, onBack, initialShowRegisterForm = false }) {
  const isAdmin = isElevatedRole(employee.role); // 관리자 또는 지원(15번)

  const [schedules, setSchedules] = useState([]);
  const [customers, setCustomers] = useState([]); // 거래처 좌표 조회용(지오펜싱 거리 계산에 필요)
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");
  const [busyId, setBusyId] = useState(null);
  const [reportTarget, setReportTarget] = useState(null); // 완료 보고 모달을 열 대상 일정
  const [showRegisterForm, setShowRegisterForm] = useState(initialShowRegisterForm && isAdmin);

  const reload = async () => {
    setStatus("loading");
    try {
      const [scheduleData, customerData] = await Promise.all([listGimhaeSchedule(), listGimhaeCustomers()]);
      setSchedules(scheduleData);
      setCustomers(customerData);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "오늘일정을 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  useEffect(() => { reload(); }, []);

  const findCustomerFor = (item) => customers.find((c) => c.customerId === item.customerId) || null;

  // 카카오내비 호출(kakaonavi:// 커스텀 스킴)은 반드시 클릭 이벤트 안에서 "동기적으로"
  // 바로 실행해야 한다. 서버 호출(markGimhaeDeparted)을 먼저 await로 기다리면 그 사이
  // "사용자 제스처" 컨텍스트가 끊겨, iOS/PWA 환경에서 커스텀 URL 스킴이 무시되고 아무
  // 반응이 없는 문제가 있었다(19번 오류). 그래서 내비 호출을 가장 먼저 동기 실행하고,
  // 출발시각 기록은 그 뒤에 비동기로 처리한다.
  const handleNavigate = (item) => {
    openKakaoNavi(findCustomerFor(item), item.customerName);
    setBusyId(item.dispatchId);
    (async () => {
      try {
        await markGimhaeDeparted(employee.employeeId, item.dispatchId);
        await reload();
      } catch (err) {
        setError(err.message || "출발시각 기록 중 오류가 발생했습니다.");
      } finally {
        setBusyId(null);
      }
    })();
  };

  const handleSubmitReport = async (reportData) => {
    const item = reportTarget;
    setBusyId(item.dispatchId);
    try {
      await completeGimhaeSchedule(employee.employeeId, item.dispatchId, reportData);
      setReportTarget(null);
      await reload();
    } finally {
      setBusyId(null);
    }
  };

  const pending = schedules.filter((s) => s.status !== "완료");
  const completed = schedules.filter((s) => s.status === "완료");

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-bold text-slate-900">오늘일정</h1>
        <div className="flex items-center gap-3">
          {isAdmin && (
            <button onClick={() => setShowRegisterForm((v) => !v)} className="flex items-center gap-1 text-xs font-bold" style={{ color: BRAND.deepGreen }}>
              <PlusCircle className="h-3.5 w-3.5" /> 일정 등록
            </button>
          )}
          <button onClick={reload} className="flex items-center gap-1 text-xs font-semibold text-slate-400">
            <RefreshCw className="h-3.5 w-3.5" /> 새로고침
          </button>
        </div>
      </div>
      <p className="mt-1 text-sm text-slate-400">거래처 순회 납품 일정과 완료처리입니다.</p>

      {showRegisterForm && (
        <GimhaeScheduleRegisterForm
          employee={employee}
          customers={customers}
          onRegistered={async () => { setShowRegisterForm(false); await reload(); }}
          onCancel={() => setShowRegisterForm(false)}
        />
      )}

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}
      {error && status !== "error" && <p className="mt-3 text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-5">
          <section>
            <p className="text-xs font-bold text-slate-500">대기중 ({pending.length})</p>
            <div className="mt-2 space-y-3">
              {pending.length === 0 && <p className="py-6 text-center text-xs text-slate-400">대기중인 일정이 없습니다.</p>}
              {pending.map((item) => {
                const busy = busyId === item.dispatchId;
                const departed = !!item.departedAt;
                return (
                  <div key={item.dispatchId} className="rounded-2xl border border-slate-200 bg-white p-4">
                    <div className="flex items-start justify-between">
                      <div>
                        <p className="text-sm font-bold text-slate-900">{item.customerName}</p>
                        <p className="text-xs text-slate-400">{item.taskDescription}</p>
                      </div>
                      <span className="rounded-full bg-slate-100 px-2 py-0.5 text-[10px] font-bold text-slate-500">{item.dispatchId}</span>
                    </div>

                    <div className="mt-2 flex items-center gap-1.5 text-[11px] text-slate-400">
                      <Clock className="h-3 w-3" />
                      {departed ? `출발 ${new Date(item.departedAt).toLocaleTimeString("ko-KR", { hour: "2-digit", minute: "2-digit" })}` : "아직 출발 전"}
                    </div>

                    <div className="mt-3 grid grid-cols-2 gap-2">
                      <button
                        onClick={() => handleNavigate(item)}
                        disabled={busy}
                        className="flex items-center justify-center gap-1.5 rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-700 disabled:opacity-50"
                      >
                        <Navigation className="h-3.5 w-3.5" /> 카카오내비로 길찾기
                      </button>
                      <button
                        onClick={() => setReportTarget(item)}
                        disabled={busy}
                        className="flex items-center justify-center gap-1.5 rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50"
                        style={{ backgroundColor: BRAND.deepGreen }}
                      >
                        <CheckCircle2 className="h-3.5 w-3.5" /> 완료 보고 제출
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </section>

          {completed.length > 0 && (
            <section>
              <p className="text-xs font-bold text-slate-500">완료 ({completed.length})</p>
              <div className="mt-2 space-y-2">
                {completed.map((item) => (
                  <div key={item.dispatchId} className="rounded-xl border border-slate-100 bg-slate-50 p-3.5">
                    <div className="flex items-center justify-between">
                      <p className="text-sm font-bold text-slate-700">{item.customerName}</p>
                      <span className="flex items-center gap-1 text-[11px] font-bold" style={{ color: BRAND.deepGreen }}>
                        <CheckCircle2 className="h-3 w-3" /> 완료
                      </span>
                    </div>
                    <p className="mt-1 text-[11px] text-slate-400">
                      {item.completedAt && new Date(item.completedAt).toLocaleString("ko-KR")} · 처리: {item.processedBy || "-"}
                    </p>
                    {item.isCrossSupport && (
                      <p className="mt-1 flex items-center gap-1 text-[11px] font-semibold text-amber-600">
                        <ArrowLeftRight className="h-3 w-3" /> 교차 지원 처리(소속: {item.workerHomeSite})
                      </p>
                    )}
                    {(item.photoUrl || item.signatureUrl) && (
                      <div className="mt-2 flex flex-wrap gap-3">
                        {item.photoUrl && (
                          <a href={item.photoUrl} target="_blank" rel="noreferrer" className="flex items-center gap-1 text-[11px] font-semibold text-slate-500">
                            <ImageIcon className="h-3.5 w-3.5" /> 현장 사진
                          </a>
                        )}
                        {item.signatureUrl && (
                          <a href={item.signatureUrl} target="_blank" rel="noreferrer" className="flex items-center gap-1 text-[11px] font-semibold text-slate-500">
                            <PenLine className="h-3.5 w-3.5" /> 서명{item.signerName ? `(${item.signerName})` : ""}
                          </a>
                        )}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </section>
          )}
        </div>
      )}

      {reportTarget && (
        <CompletionReportModal
          item={reportTarget}
          customer={findCustomerFor(reportTarget)}
          onClose={() => setReportTarget(null)}
          onSubmit={handleSubmitReport}
        />
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 김해 — 오늘일정 등록 폼(관리자 전용). 거래처를 검색해서 고르고 작업내용을
// 입력하면 createGimhaeSchedule 액션으로 새 배차 항목이 만들어진다.
// ────────────────────────────────────────────────────────────────────────
function GimhaeScheduleRegisterForm({ employee, customers, onRegistered, onCancel }) {
  const [query, setQuery] = useState("");
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [taskDescription, setTaskDescription] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const filtered = query.trim()
    ? customers.filter((c) => String(c.customerName).toLowerCase().includes(query.trim().toLowerCase()))
    : customers;

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedCustomer) {
      setError("거래처를 선택해주세요.");
      return;
    }
    if (!taskDescription.trim()) {
      setError("작업내용을 입력해주세요.");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      await createGimhaeSchedule(employee.employeeId, {
        customerId: selectedCustomer.customerId,
        customerName: selectedCustomer.customerName,
        taskDescription: taskDescription.trim(),
      });
      onRegistered();
    } catch (err) {
      setError(err.message || "등록 중 오류가 발생했습니다.");
      setSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="mt-4 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
      <div>
        <label className="text-xs font-semibold text-slate-500">거래처 검색 *</label>
        <input
          value={selectedCustomer ? selectedCustomer.customerName : query}
          onChange={(e) => { setQuery(e.target.value); setSelectedCustomer(null); }}
          placeholder="거래처명으로 검색"
          disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
        />
        {!selectedCustomer && query.trim() && (
          <div className="mt-1.5 max-h-40 overflow-y-auto rounded-lg border border-slate-100">
            {filtered.length === 0 && <p className="px-3 py-2 text-xs text-slate-400">검색 결과가 없습니다.</p>}
            {filtered.map((c) => (
              <button
                key={c.customerId}
                type="button"
                onClick={() => { setSelectedCustomer(c); setQuery(""); }}
                className="block w-full px-3 py-2 text-left text-xs text-slate-700 hover:bg-slate-50"
              >
                <span className="font-semibold">{c.customerName}</span>
                <span className="ml-1.5 text-slate-400">{c.region}</span>
              </button>
            ))}
          </div>
        )}
        {selectedCustomer && (
          <p className="mt-1 text-[11px] text-slate-400">{selectedCustomer.deliveryAddress}</p>
        )}
      </div>

      <div>
        <label className="text-xs font-semibold text-slate-500">작업내용 *</label>
        <input
          value={taskDescription}
          onChange={(e) => setTaskDescription(e.target.value)}
          placeholder="예: 정기 납품, 부품 회수 등"
          disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
        />
      </div>

      {error && <p className="text-xs font-semibold text-red-500">{error}</p>}

      <div className="grid grid-cols-2 gap-2">
        <button type="button" onClick={onCancel} disabled={submitting} className="rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-600 disabled:opacity-50">
          취소
        </button>
        <button type="submit" disabled={submitting} className="rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: BRAND.deepGreen }}>
          {submitting ? "등록중..." : "일정 등록"}
        </button>
      </div>
    </form>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 김해 — 납품경로 타임라인(관리자 전용, 7번 요청 대응). 날짜를 고르면 그날
// 완료된 일정을 처리기사별로 묶어 방문 순서대로 보여주고, "전체 경로 지도에서
// 보기"를 누르면 그 기사가 그날 방문한 거래처들을 순서대로 이은 지도가
// 새 탭으로 열린다(Google 지도, API 키 불필요).
// ────────────────────────────────────────────────────────────────────────
function GimhaeDeliveryHistoryScreen({ employee, onBack }) {
  const todayStr = (() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}-${String(now.getDate()).padStart(2, "0")}`;
  })();
  const [date, setDate] = useState(todayStr);
  const [drivers, setDrivers] = useState([]);
  const [expandedWorker, setExpandedWorker] = useState(null);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");

  const reload = async (targetDate) => {
    setStatus("loading");
    try {
      const data = await listGimhaeDeliveryHistory(employee.employeeId, targetDate);
      setDrivers(data.drivers);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "납품경로 기록을 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  useEffect(() => { reload(date); }, []);

  const formatTime = (iso) => {
    if (!iso) return "-";
    const d = new Date(iso);
    if (isNaN(d.getTime())) return "-";
    return d.toLocaleTimeString("ko-KR", { hour: "2-digit", minute: "2-digit" });
  };

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">납품경로 타임라인</h1>
      <p className="mt-1 text-sm text-slate-400">날짜를 선택하면 그날 기사별로 방문한 거래처 순서를 볼 수 있습니다.</p>

      <div className="mt-4 flex items-center gap-2">
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)}
          className="rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none" />
        <button onClick={() => reload(date)} className="flex items-center gap-1 rounded-lg border border-slate-200 px-3 py-2 text-xs font-bold text-slate-600">
          <RefreshCw className="h-3.5 w-3.5" /> 조회
        </button>
      </div>

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-3">
          {drivers.length === 0 && <p className="py-8 text-center text-xs text-slate-400">이 날짜에 완료된 납품 기록이 없습니다.</p>}
          {drivers.map((d) => {
            const expanded = expandedWorker === d.workerName;
            const routeUrl = buildRouteMapUrl(d.stops);
            const missingCoordCount = d.stops.filter((s) => s.latitude == null || s.longitude == null).length;
            return (
              <div key={d.workerName} className="rounded-xl border border-slate-200 bg-white p-4">
                <button onClick={() => setExpandedWorker(expanded ? null : d.workerName)} className="flex w-full items-center justify-between text-left">
                  <span>
                    <p className="text-sm font-bold text-slate-900">{d.workerName}</p>
                    <p className="text-xs text-slate-400">납품 {d.stopCount}건</p>
                  </span>
                  <Clock className="h-4 w-4 text-slate-300" />
                </button>

                {expanded && (
                  <>
                    <div className="mt-3 space-y-0">
                      {d.stops.map((s, idx) => (
                        <div key={s.dispatchId} className="flex gap-3">
                          <div className="flex flex-col items-center">
                            <span className="flex h-6 w-6 flex-shrink-0 items-center justify-center rounded-full text-[11px] font-bold text-white" style={{ backgroundColor: BRAND.deepGreen }}>
                              {s.visitOrder}
                            </span>
                            {idx < d.stops.length - 1 && <span className="mt-0.5 h-full w-px flex-1 bg-slate-200" />}
                          </div>
                          <div className="flex-1 pb-3">
                            <p className="text-sm font-bold text-slate-900">{s.customerName}</p>
                            <p className="text-xs text-slate-400">{s.deliveryAddress || "주소 미등록"}</p>
                            <p className="mt-0.5 text-[11px] text-slate-400">
                              출발 {formatTime(s.departedAt)} → 완료 {formatTime(s.completedAt)}
                              {(s.latitude == null || s.longitude == null) && (
                                <span className="ml-1 font-semibold text-amber-600">· 좌표 미등록</span>
                              )}
                            </p>
                          </div>
                        </div>
                      ))}
                    </div>

                    {routeUrl ? (
                      <a href={routeUrl} target="_blank" rel="noopener noreferrer"
                        className="mt-1 flex items-center justify-center gap-1.5 rounded-lg py-2.5 text-xs font-bold text-white"
                        style={{ backgroundColor: BRAND.deepGreen }}>
                        <MapPin className="h-3.5 w-3.5" /> 전체 경로 지도에서 보기
                      </a>
                    ) : (
                      <p className="mt-1 text-center text-[11px] text-slate-400">좌표가 등록된 거래처가 없어 지도를 표시할 수 없습니다.</p>
                    )}
                    {routeUrl && missingCoordCount > 0 && (
                      <p className="mt-1.5 text-center text-[11px] text-amber-600">좌표가 없는 거래처 {missingCoordCount}곳은 지도 경로에서 제외됩니다.</p>
                    )}
                  </>
                )}
              </div>
            );
          })}
        </div>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 김해 — 거래처정보 화면. 거래처ID가 없는 행은 조회 시 서버가 자동 발급한다.
// 관리자는 신규 거래처 등록 및 기존 거래처 주소 수정이 가능하며, 두 경우
// 모두 서버가 저장 직전에 주소를 지오코딩해 위도/경도를 함께 기록한다
// (GPS 지오펜싱이 이 좌표를 기준으로 거리 계산을 하기 때문에 필수적이다).
// ────────────────────────────────────────────────────────────────────────
function GimhaeCustomerScreen({ employee, onBack }) {
  const isAdmin = isElevatedRole(employee.role); // 관리자 또는 지원(15번)
  const [customers, setCustomers] = useState([]);
  const [query, setQuery] = useState("");
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");
  const [showAddForm, setShowAddForm] = useState(false);
  const [editTarget, setEditTarget] = useState(null); // 주소 수정 중인 거래처

  const reload = async () => {
    setStatus("loading");
    try {
      const data = await listGimhaeCustomers();
      setCustomers(data);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "거래처 목록을 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  useEffect(() => { reload(); }, []);

  const filtered = customers.filter((c) => {
    if (!query.trim()) return true;
    const q = query.trim().toLowerCase();
    return String(c.customerName).toLowerCase().includes(q) || String(c.region || "").toLowerCase().includes(q);
  });

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-bold text-slate-900">거래처정보</h1>
        {isAdmin && (
          <button onClick={() => setShowAddForm((v) => !v)} className="flex items-center gap-1 text-xs font-bold" style={{ color: BRAND.deepGreen }}>
            <PlusCircle className="h-3.5 w-3.5" /> 거래처 등록
          </button>
        )}
      </div>
      <p className="mt-1 text-sm text-slate-400">납품 거래처 목록입니다. 주소는 등록·수정 시 자동으로 좌표(위경도)로 변환됩니다.</p>

      {showAddForm && (
        <GimhaeCustomerForm
          employee={employee}
          mode="create"
          onDone={async () => { setShowAddForm(false); await reload(); }}
          onCancel={() => setShowAddForm(false)}
        />
      )}

      <div className="mt-5 flex items-center gap-2 rounded-lg border border-slate-200 px-3 py-2.5">
        <Search className="h-4 w-4 text-slate-400" />
        <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="거래처명 또는 지역 검색"
          className="w-full text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none" />
      </div>

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-2">
          {filtered.length === 0 && <p className="py-8 text-center text-xs text-slate-400">검색 결과가 없습니다.</p>}
          {filtered.map((c) => (
            <div key={c.customerId} className="rounded-xl border border-slate-200 bg-white p-4">
              <div className="flex items-center justify-between">
                <p className="text-sm font-bold text-slate-900">{c.customerName}</p>
                <span className="rounded-full bg-slate-100 px-2 py-0.5 text-[10px] font-bold text-slate-500">{c.customerId}</span>
              </div>
              <p className="mt-1 text-xs text-slate-500">{c.deliveryAddress}</p>
              <div className="mt-1.5 flex items-center justify-between">
                <p className="text-[11px] text-slate-400">
                  {c.region ? `지역: ${c.region} · ` : ""}
                  {c.latitude != null && c.longitude != null ? (
                    <span style={{ color: BRAND.deepGreen }}>좌표 등록됨</span>
                  ) : (
                    <span className="font-semibold text-amber-600">좌표 미등록(지오펜싱 불가)</span>
                  )}
                </p>
                {isAdmin && (
                  <button onClick={() => setEditTarget(editTarget?.customerId === c.customerId ? null : c)} className="text-[11px] font-semibold text-slate-400">
                    주소 수정
                  </button>
                )}
              </div>
              {editTarget?.customerId === c.customerId && (
                <GimhaeCustomerForm
                  employee={employee}
                  mode="edit"
                  customer={c}
                  onDone={async () => { setEditTarget(null); await reload(); }}
                  onCancel={() => setEditTarget(null)}
                />
              )}
            </div>
          ))}
        </div>
      )}
    </main>
  );
}

/**
 * 김해 — 거래처 등록/주소수정 공용 폼.
 *   mode="create": 거래처명+주소(+지역)를 받아 registerGimhaeCustomer 호출.
 *   mode="edit"  : 기존 거래처의 주소(+지역)만 받아 updateGimhaeCustomerAddress 호출.
 * 두 액션 모두 서버가 저장 직전에 주소를 지오코딩하므로, 성공 응답에 담겨 오는
 * latitude/longitude로 "좌표 등록됨/실패" 여부를 바로 알려준다.
 */
function GimhaeCustomerForm({ employee, mode, customer, onDone, onCancel }) {
  const [customerName, setCustomerName] = useState(mode === "edit" ? customer.customerName : "");
  const [address, setAddress] = useState(mode === "edit" ? customer.deliveryAddress : "");
  const [region, setRegion] = useState(mode === "edit" ? (customer.region || "") : "");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [geocodeResult, setGeocodeResult] = useState(null); // { geocoded, latitude, longitude }

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (mode === "create" && !customerName.trim()) {
      setError("거래처명을 입력해주세요.");
      return;
    }
    if (!address.trim()) {
      setError("납품주소를 입력해주세요.");
      return;
    }
    setError("");
    setGeocodeResult(null);
    setSubmitting(true);
    try {
      let result;
      if (mode === "create") {
        result = await registerGimhaeCustomer(employee.employeeId, {
          customerName: customerName.trim(),
          deliveryAddress: address.trim(),
          region: region.trim(),
        });
      } else {
        result = await updateGimhaeCustomerAddress(employee.employeeId, {
          customerId: customer.customerId,
          deliveryAddress: address.trim(),
          region: region.trim(),
        });
      }

      if (!result.geocoded) {
        // 주소 저장은 성공했지만 좌표 변환이 안 된 경우 — 바로 닫지 않고 안내만 보여준다.
        setGeocodeResult(result);
        setSubmitting(false);
        return;
      }
      onDone();
    } catch (err) {
      setError(err.message || "처리 중 오류가 발생했습니다.");
      setSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="mt-3 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
      {mode === "create" && (
        <div>
          <label className="text-xs font-semibold text-slate-500">거래처명 *</label>
          <input value={customerName} onChange={(e) => setCustomerName(e.target.value)} disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
        </div>
      )}
      <div>
        <label className="text-xs font-semibold text-slate-500">납품주소 *</label>
        <input value={address} onChange={(e) => setAddress(e.target.value)} placeholder="도로명 주소를 입력하면 자동으로 좌표가 계산됩니다" disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
      </div>
      <div>
        <label className="text-xs font-semibold text-slate-500">지역구분</label>
        <input value={region} onChange={(e) => setRegion(e.target.value)} disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
      </div>

      {error && <p className="text-xs font-semibold text-red-500">{error}</p>}
      {geocodeResult && !geocodeResult.geocoded && (
        <div className="rounded-lg border border-amber-200 bg-amber-50 p-3 text-[11px] text-amber-700">
          주소는 저장됐지만 좌표 변환에 실패했습니다(주소를 정확히 인식하지 못함). 이 거래처는 GPS 지오펜싱 거리 비교 없이 완료 보고가 처리됩니다. 주소를 더 구체적으로(도로명+번지) 다시 입력해보세요.
          <button type="button" onClick={onDone} className="mt-2 block font-bold underline">그래도 닫기</button>
        </div>
      )}

      <div className="grid grid-cols-2 gap-2">
        <button type="button" onClick={onCancel} disabled={submitting} className="rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-600 disabled:opacity-50">
          취소
        </button>
        <button type="submit" disabled={submitting} className="rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: BRAND.deepGreen }}>
          {submitting ? "처리중..." : mode === "create" ? "거래처 등록" : "주소 저장"}
        </button>
      </div>
    </form>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 김해 — 차량관리 화면(법인차량(김해) 시트). 차량 등록/주행거리 등록/보험·연비
// 수정을 모두 이 화면에서 처리한다. 주행거리는 직접 입력값을 덮어쓰지 않고
// "거리 추가" 방식으로만 누적되도록 해 사고 입력으로 누적치가 어긋나는 걸 막는다.
// ────────────────────────────────────────────────────────────────────────
function GimhaeVehicleScreen({ employee, onBack }) {
  const isAdmin = isElevatedRole(employee.role); // 관리자 또는 지원(15번)
  const [vehicles, setVehicles] = useState([]);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");
  const [showAddForm, setShowAddForm] = useState(false);
  const [mileageTarget, setMileageTarget] = useState(null); // 주행거리 등록 중인 차량
  const [fuelTarget, setFuelTarget] = useState(null); // 주유 등록 중인 차량
  const [editTarget, setEditTarget] = useState(null); // 보험/연비 수정 중인 차량

  const reload = async () => {
    setStatus("loading");
    try {
      const data = await listVehicles();
      setVehicles(data);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "차량 목록을 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  useEffect(() => { reload(); }, []);

  const isExpiringSoon = (dateStr) => {
    if (!dateStr) return false;
    const expiry = new Date(dateStr);
    if (isNaN(expiry.getTime())) return false;
    const days = (expiry.getTime() - Date.now()) / (1000 * 60 * 60 * 24);
    return days >= 0 && days <= 30;
  };

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-bold text-slate-900">차량관리</h1>
        {isAdmin && (
          <button onClick={() => setShowAddForm((v) => !v)} className="flex items-center gap-1 text-xs font-bold" style={{ color: BRAND.deepGreen }}>
            <PlusCircle className="h-3.5 w-3.5" /> 차량 등록
          </button>
        )}
      </div>
      <p className="mt-1 text-sm text-slate-400">법인·개인 차량 현황 및 보험 정보입니다.</p>

      {showAddForm && (
        <GimhaeVehicleRegisterForm
          employee={employee}
          onDone={async () => { setShowAddForm(false); await reload(); }}
          onCancel={() => setShowAddForm(false)}
        />
      )}

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && (
        <div className="mt-5 space-y-2">
          {vehicles.length === 0 && <p className="py-8 text-center text-xs text-slate-400">등록된 차량이 없습니다.</p>}
          {vehicles.map((v) => {
            const expiringSoon = isExpiringSoon(v.insuranceExpiry);
            return (
              <div key={v.label} className="rounded-xl border border-slate-200 bg-white p-4">
                <div className="flex items-center justify-between">
                  <p className="text-sm font-bold text-slate-900">{v.label}</p>
                  <span className="rounded-full px-2 py-0.5 text-[10px] font-bold text-white" style={{ backgroundColor: v.ownershipType === "법인" ? BRAND.deepGreen : "#94a3b8" }}>
                    {v.ownershipType || "구분 미입력"}
                  </span>
                </div>
                <p className="mt-1 text-xs text-slate-500">
                  현재 주행거리: {v.mileage ? `${v.mileage}km` : "0km"}
                  {v.fuelEfficiencyKmpl ? ` · 연비 ${v.fuelEfficiencyKmpl}km/L` : ""}
                </p>
                <p className="mt-1 text-[11px] text-slate-400">
                  보험 {v.insuranceStart || "-"} 시작 · {v.insurancePeriodYears ? `${v.insurancePeriodYears}년` : "-"} · 만료 {v.insuranceExpiry || "-"}
                </p>
                {expiringSoon && (
                  <p className="mt-1.5 flex items-center gap-1 text-[11px] font-semibold text-amber-600">
                    <AlertTriangle className="h-3 w-3" /> 보험 만료 30일 이내 — 갱신 필요
                  </p>
                )}

                <div className="mt-2.5 flex items-center gap-3">
                  <button onClick={() => { setMileageTarget(mileageTarget === v.label ? null : v.label); setFuelTarget(null); setEditTarget(null); }} className="text-[11px] font-semibold" style={{ color: BRAND.deepGreen }}>
                    주행거리 등록
                  </button>
                  <button onClick={() => { setFuelTarget(fuelTarget === v.label ? null : v.label); setMileageTarget(null); setEditTarget(null); }} className="flex items-center gap-1 text-[11px] font-semibold" style={{ color: BRAND.deepGreen }}>
                    <Fuel className="h-3 w-3" /> 주유 등록
                  </button>
                  {isAdmin && (
                    <button onClick={() => { setEditTarget(editTarget === v.label ? null : v.label); setMileageTarget(null); setFuelTarget(null); }} className="text-[11px] font-semibold text-slate-400">
                      보험·연비 수정
                    </button>
                  )}
                </div>

                {mileageTarget === v.label && (
                  <VehicleMileageForm
                    employee={employee}
                    vehicle={v}
                    onDone={async () => { setMileageTarget(null); await reload(); }}
                    onCancel={() => setMileageTarget(null)}
                  />
                )}
                {fuelTarget === v.label && (
                  <VehicleFuelPurchaseForm
                    employee={employee}
                    vehicle={v}
                    onDone={() => setFuelTarget(null)}
                    onCancel={() => setFuelTarget(null)}
                  />
                )}
                {editTarget === v.label && (
                  <VehicleInsuranceForm
                    employee={employee}
                    vehicle={v}
                    onDone={async () => { setEditTarget(null); await reload(); }}
                    onCancel={() => setEditTarget(null)}
                  />
                )}
              </div>
            );
          })}
        </div>
      )}
    </main>
  );
}

/** 차량 신규 등록 폼(관리자 전용) — "+ 차량 등록" 버튼으로 토글된다. */
function GimhaeVehicleRegisterForm({ employee, onDone, onCancel }) {
  const [vehicleLabel, setVehicleLabel] = useState("");
  const [ownershipType, setOwnershipType] = useState("법인");
  const [initialMileage, setInitialMileage] = useState("");
  const [insuranceStartDate, setInsuranceStartDate] = useState("");
  const [insurancePeriodYears, setInsurancePeriodYears] = useState("");
  const [fuelEfficiencyKmpl, setFuelEfficiencyKmpl] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!vehicleLabel.trim()) {
      setError("차종(차량번호)을 입력해주세요. 예: 카니발(12가3456)");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      await registerVehicle(employee.employeeId, {
        vehicleLabel: vehicleLabel.trim(),
        ownershipType,
        initialMileage: initialMileage ? Number(initialMileage) : 0,
        insuranceStartDate,
        insurancePeriodYears: insurancePeriodYears ? Number(insurancePeriodYears) : "",
        fuelEfficiencyKmpl: fuelEfficiencyKmpl ? Number(fuelEfficiencyKmpl) : "",
      });
      onDone();
    } catch (err) {
      setError(err.message || "차량 등록 중 오류가 발생했습니다.");
      setSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="mt-3 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
      <div>
        <label className="text-xs font-semibold text-slate-500">차종(차량번호) *</label>
        <input value={vehicleLabel} onChange={(e) => setVehicleLabel(e.target.value)} placeholder="예: 카니발(12가3456)" disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
      </div>
      <div>
        <label className="text-xs font-semibold text-slate-500">구분</label>
        <div className="mt-1.5 grid grid-cols-2 gap-2">
          {["법인", "개인"].map((opt) => (
            <button key={opt} type="button" onClick={() => setOwnershipType(opt)} disabled={submitting}
              className={`rounded-lg py-2 text-xs font-bold ${ownershipType === opt ? "text-white" : "border border-slate-200 text-slate-500"}`}
              style={ownershipType === opt ? { backgroundColor: BRAND.deepGreen } : {}}>
              {opt}
            </button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-2 gap-2">
        <div>
          <label className="text-xs font-semibold text-slate-500">최초 주행거리(km)</label>
          <input type="number" value={initialMileage} onChange={(e) => setInitialMileage(e.target.value)} placeholder="0" disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">연비(km/L)</label>
          <input type="number" step="0.1" value={fuelEfficiencyKmpl} onChange={(e) => setFuelEfficiencyKmpl(e.target.value)} placeholder="미입력 시 회사 평균값 적용" disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
        </div>
      </div>
      <div className="grid grid-cols-2 gap-2">
        <div>
          <label className="text-xs font-semibold text-slate-500">보험 가입일</label>
          <input type="date" value={insuranceStartDate} onChange={(e) => setInsuranceStartDate(e.target.value)} disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">보험 기간(년)</label>
          <input type="number" value={insurancePeriodYears} onChange={(e) => setInsurancePeriodYears(e.target.value)} placeholder="예: 1" disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
        </div>
      </div>

      {error && <p className="text-xs font-semibold text-red-500">{error}</p>}

      <div className="grid grid-cols-2 gap-2">
        <button type="button" onClick={onCancel} disabled={submitting} className="rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-600 disabled:opacity-50">
          취소
        </button>
        <button type="submit" disabled={submitting} className="rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: BRAND.deepGreen }}>
          {submitting ? "처리중..." : "차량 등록"}
        </button>
      </div>
    </form>
  );
}

/** 주행거리 등록 폼 — 입력한 거리만큼 현재 주행거리에 자동으로 더해(누적)지고, 예상 유류비가 함께 계산된다. */
function VehicleMileageForm({ employee, vehicle, onDone, onCancel }) {
  const [distanceKm, setDistanceKm] = useState("");
  const [note, setNote] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [result, setResult] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const km = Number(distanceKm);
    if (!km || km <= 0) {
      setError("0보다 큰 주행거리(km)를 입력해주세요.");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      const data = await registerVehicleMileage(employee.employeeId, { vehicleLabel: vehicle.label, distanceKm: km, note: note.trim() });
      setResult(data);
      setSubmitting(false);
    } catch (err) {
      setError(err.message || "주행거리 등록 중 오류가 발생했습니다.");
      setSubmitting(false);
    }
  };

  if (result) {
    return (
      <div className="mt-3 rounded-xl border border-slate-200 bg-white p-4 text-xs">
        <p className="font-bold" style={{ color: BRAND.deepGreen }}>등록 완료</p>
        <p className="mt-1 text-slate-500">누적 주행거리: {result.currentMileage}km · 이번 거리 예상 유류비: {Number(result.estimatedFuelCost).toLocaleString()}원</p>
        <button onClick={onDone} className="mt-2 font-bold underline text-slate-400">닫기</button>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="mt-3 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
      <div>
        <label className="text-xs font-semibold text-slate-500">이번에 이동한 거리(km) *</label>
        <input type="number" step="0.1" value={distanceKm} onChange={(e) => setDistanceKm(e.target.value)} placeholder="예: 42.5" disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
        <p className="mt-1 text-[11px] text-slate-400">현재 누적 주행거리({vehicle.mileage || 0}km)에 이 거리만큼 더해집니다.</p>
      </div>
      <div>
        <label className="text-xs font-semibold text-slate-500">메모</label>
        <input value={note} onChange={(e) => setNote(e.target.value)} placeholder="선택 입력" disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
      </div>

      {error && <p className="text-xs font-semibold text-red-500">{error}</p>}

      <div className="grid grid-cols-2 gap-2">
        <button type="button" onClick={onCancel} disabled={submitting} className="rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-600 disabled:opacity-50">
          취소
        </button>
        <button type="submit" disabled={submitting} className="rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: BRAND.deepGreen }}>
          {submitting ? "처리중..." : "주행거리 등록"}
        </button>
      </div>
    </form>
  );
}

/**
 * 주유 등록(11번 요청) — 실제 결제한 주유금액/주유량을 그대로 기록한다.
 * 주행거리 기반 "예상 유류비"와는 별개로 남아, 유류비 대시보드에서 두 값을
 * 비교해볼 수 있게 한다(연비값이 실제와 동떨어져 있으면 차이가 크게 난다).
 */
function VehicleFuelPurchaseForm({ employee, vehicle, onDone, onCancel }) {
  const [amountWon, setAmountWon] = useState("");
  const [liters, setLiters] = useState("");
  const [date, setDate] = useState(() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}-${String(now.getDate()).padStart(2, "0")}`;
  });
  const [note, setNote] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [done, setDone] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const amount = Number(amountWon);
    if (!amount || amount <= 0) {
      setError("0보다 큰 주유금액(원)을 입력해주세요.");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      await registerFuelPurchase(employee.employeeId, {
        vehicleLabel: vehicle.label,
        amountWon: amount,
        liters: liters ? Number(liters) : "",
        date,
        note: note.trim(),
      });
      setDone(true);
      setSubmitting(false);
    } catch (err) {
      setError(err.message || "주유 등록 중 오류가 발생했습니다.");
      setSubmitting(false);
    }
  };

  if (done) {
    return (
      <div className="mt-3 rounded-xl border border-slate-200 bg-white p-4 text-xs">
        <p className="font-bold" style={{ color: BRAND.deepGreen }}>주유 등록 완료</p>
        <p className="mt-1 text-slate-500">{date} · {Number(amountWon).toLocaleString()}원{liters ? ` · ${liters}L` : ""}</p>
        <button onClick={onDone} className="mt-2 font-bold underline text-slate-400">닫기</button>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="mt-3 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
      <div className="grid grid-cols-2 gap-2">
        <div>
          <label className="text-xs font-semibold text-slate-500">주유금액(원) *</label>
          <input type="number" value={amountWon} onChange={(e) => setAmountWon(e.target.value)} placeholder="예: 70000" disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">주유량(L)</label>
          <input type="number" step="0.1" value={liters} onChange={(e) => setLiters(e.target.value)} placeholder="선택 입력" disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
        </div>
      </div>
      <div>
        <label className="text-xs font-semibold text-slate-500">주유 일자</label>
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)} disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
      </div>
      <div>
        <label className="text-xs font-semibold text-slate-500">메모</label>
        <input value={note} onChange={(e) => setNote(e.target.value)} placeholder="선택 입력" disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
      </div>

      {error && <p className="text-xs font-semibold text-red-500">{error}</p>}

      <div className="grid grid-cols-2 gap-2">
        <button type="button" onClick={onCancel} disabled={submitting} className="rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-600 disabled:opacity-50">
          취소
        </button>
        <button type="submit" disabled={submitting} className="rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: BRAND.deepGreen }}>
          {submitting ? "처리중..." : "주유 등록"}
        </button>
      </div>
    </form>
  );
}

/** 보험·연비·구분 수정 폼(관리자 전용) — 주행거리는 이 폼에서 바꿀 수 없다(VehicleMileageForm으로 분리). */
function VehicleInsuranceForm({ employee, vehicle, onDone, onCancel }) {
  const [ownershipType, setOwnershipType] = useState(vehicle.ownershipType || "법인");
  const [insuranceStartDate, setInsuranceStartDate] = useState(vehicle.insuranceStart || "");
  const [insurancePeriodYears, setInsurancePeriodYears] = useState(vehicle.insurancePeriodYears || "");
  const [fuelEfficiencyKmpl, setFuelEfficiencyKmpl] = useState(vehicle.fuelEfficiencyKmpl || "");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSubmitting(true);
    try {
      await updateVehicleInsurance(employee.employeeId, {
        vehicleLabel: vehicle.label,
        ownershipType,
        insuranceStartDate,
        insurancePeriodYears: insurancePeriodYears ? Number(insurancePeriodYears) : "",
        fuelEfficiencyKmpl: fuelEfficiencyKmpl ? Number(fuelEfficiencyKmpl) : "",
      });
      onDone();
    } catch (err) {
      setError(err.message || "차량 정보 수정 중 오류가 발생했습니다.");
      setSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="mt-3 space-y-3 rounded-xl border border-slate-200 bg-white p-4">
      <div>
        <label className="text-xs font-semibold text-slate-500">구분</label>
        <div className="mt-1.5 grid grid-cols-2 gap-2">
          {["법인", "개인"].map((opt) => (
            <button key={opt} type="button" onClick={() => setOwnershipType(opt)} disabled={submitting}
              className={`rounded-lg py-2 text-xs font-bold ${ownershipType === opt ? "text-white" : "border border-slate-200 text-slate-500"}`}
              style={ownershipType === opt ? { backgroundColor: BRAND.deepGreen } : {}}>
              {opt}
            </button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-2 gap-2">
        <div>
          <label className="text-xs font-semibold text-slate-500">보험 가입일</label>
          <input type="date" value={insuranceStartDate} onChange={(e) => setInsuranceStartDate(e.target.value)} disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
        </div>
        <div>
          <label className="text-xs font-semibold text-slate-500">보험 기간(년)</label>
          <input type="number" value={insurancePeriodYears} onChange={(e) => setInsurancePeriodYears(e.target.value)} disabled={submitting}
            className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none disabled:opacity-50" />
        </div>
      </div>
      <div>
        <label className="text-xs font-semibold text-slate-500">연비(km/L)</label>
        <input type="number" step="0.1" value={fuelEfficiencyKmpl} onChange={(e) => setFuelEfficiencyKmpl(e.target.value)} placeholder="미입력 시 회사 평균값 적용" disabled={submitting}
          className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
      </div>

      {error && <p className="text-xs font-semibold text-red-500">{error}</p>}

      <div className="grid grid-cols-2 gap-2">
        <button type="button" onClick={onCancel} disabled={submitting} className="rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-600 disabled:opacity-50">
          취소
        </button>
        <button type="submit" disabled={submitting} className="rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: BRAND.deepGreen }}>
          {submitting ? "처리중..." : "저장"}
        </button>
      </div>
    </form>
  );
}

/**
 * 김해 — 유류비 관리 대시보드(관리자 전용). 월을 선택하면 그 달의 차량별
 * 총 주행거리/예상유류비를 한 화면에 표로 보여준다. (4+6번 현장 요청 대응)
 */
function FuelCostDashboardScreen({ employee, onBack }) {
  const defaultMonth = (() => {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
  })();
  const [yearMonth, setYearMonth] = useState(defaultMonth);
  const [dashboard, setDashboard] = useState(null);
  const [status, setStatus] = useState("loading");
  const [error, setError] = useState("");

  const reload = async (month) => {
    setStatus("loading");
    try {
      const data = await getFuelCostDashboard(employee.employeeId, month);
      setDashboard(data);
      setStatus("ready");
    } catch (err) {
      setError(err.message || "유류비 데이터를 불러오지 못했습니다.");
      setStatus("error");
    }
  };

  useEffect(() => { reload(yearMonth); }, []);

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">유류비 관리</h1>
      <p className="mt-1 text-sm text-slate-400">월별 차량별 주행거리 기반 "예상 유류비"와, 주유 등록으로 쌓인 "실제 주유비"를 함께 보여줍니다.</p>

      <div className="mt-4 flex items-center gap-2">
        <input type="month" value={yearMonth} onChange={(e) => setYearMonth(e.target.value)}
          className="rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 focus:outline-none" />
        <button onClick={() => reload(yearMonth)} className="flex items-center gap-1 rounded-lg border border-slate-200 px-3 py-2 text-xs font-bold text-slate-600">
          <RefreshCw className="h-3.5 w-3.5" /> 조회
        </button>
      </div>

      {status === "loading" && <p className="mt-6 text-center text-xs text-slate-400">불러오는 중...</p>}
      {status === "error" && <p className="mt-6 text-center text-xs font-semibold text-red-500">{error}</p>}

      {status === "ready" && dashboard && (
        <>
          <div className="mt-5 grid grid-cols-2 gap-2">
            <div className="rounded-xl p-4 text-white" style={{ backgroundColor: BRAND.deepGreen }}>
              <p className="text-xs opacity-80">{dashboard.yearMonth} 예상 유류비</p>
              <p className="mt-1 text-xl font-bold">{Number(dashboard.totalFuelCost || 0).toLocaleString()}원</p>
              <p className="mt-0.5 text-[11px] opacity-80">총 주행거리 {Number(dashboard.totalDistanceKm || 0).toLocaleString()}km</p>
            </div>
            <div className="rounded-xl border border-slate-200 bg-white p-4">
              <p className="text-xs text-slate-400">{dashboard.yearMonth} 실제 주유비</p>
              <p className="mt-1 text-xl font-bold text-slate-800">{Number(dashboard.totalActualFuelCost || 0).toLocaleString()}원</p>
              <p className="mt-0.5 text-[11px] text-slate-400">주유 영수증 등록 기준</p>
            </div>
          </div>

          <div className="mt-4 space-y-2">
            {dashboard.vehicles.length === 0 && <p className="py-8 text-center text-xs text-slate-400">등록된 차량이 없습니다.</p>}
            {dashboard.vehicles.map((v) => (
              <div key={v.vehicleLabel} className="rounded-xl border border-slate-200 bg-white p-4">
                <div className="flex items-center justify-between">
                  <p className="text-sm font-bold text-slate-900">{v.vehicleLabel}</p>
                  <span className="rounded-full px-2 py-0.5 text-[10px] font-bold text-white" style={{ backgroundColor: v.ownershipType === "법인" ? BRAND.deepGreen : "#94a3b8" }}>
                    {v.ownershipType || "구분 미입력"}
                  </span>
                </div>
                <p className="mt-1 text-xs text-slate-500">
                  주행거리 {Number(v.totalDistanceKm || 0).toLocaleString()}km · 등록 {v.logCount}건
                  {v.fuelEfficiencyKmpl ? ` · 연비 ${v.fuelEfficiencyKmpl}km/L` : " · 연비 미등록(회사 평균값 적용)"}
                </p>
                <div className="mt-2 grid grid-cols-2 gap-2 rounded-lg bg-slate-50 p-2 text-center">
                  <div>
                    <p className="text-[10px] text-slate-400">예상 유류비</p>
                    <p className="text-sm font-bold" style={{ color: BRAND.deepGreen }}>{Number(v.totalFuelCost || 0).toLocaleString()}원</p>
                  </div>
                  <div>
                    <p className="text-[10px] text-slate-400">실제 주유비({v.fuelPurchaseCount || 0}건)</p>
                    <p className="text-sm font-bold text-slate-700">{Number(v.actualFuelCost || 0).toLocaleString()}원</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// 김해 홈화면 — 오늘일정/거래처정보/법인차량으로 분기한다.
// ────────────────────────────────────────────────────────────────────────
/**
 * 김해 "업체 긴급요청" 등록 화면(18번 요청) — 거래처 현장에서 급하게 들어온
 * 요청을 등록한다. 등록되면 알림 목록에 빨간색으로 표시된다.
 */
function GimhaeUrgentRequestScreen({ employee, onBack }) {
  const [customerName, setCustomerName] = useState("");
  const [message, setMessage] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [done, setDone] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!message.trim()) {
      setError("요청 내용을 입력해주세요.");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      await registerGimhaeUrgentRequest(employee.employeeId, message.trim(), customerName.trim());
      setDone(true);
    } catch (err) {
      setError(err.message || "긴급요청 등록 중 오류가 발생했습니다.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <main className="mx-auto max-w-md px-6 py-8">
      <button onClick={onBack} className="mb-4 text-xs font-semibold text-slate-400">← 홈으로</button>
      <h1 className="text-xl font-bold text-slate-900">업체 긴급요청</h1>
      <p className="mt-1 text-sm text-slate-400">거래처 현장에서 급하게 들어온 요청을 등록해주세요. 등록되면 전체 알림에 빨간색으로 표시됩니다.</p>

      {done ? (
        <div className="mt-6 rounded-xl border border-slate-200 bg-white p-4 text-center">
          <p className="text-sm font-bold" style={{ color: BRAND.deepGreen }}>긴급요청이 등록되었습니다.</p>
          <button onClick={() => { setDone(false); setMessage(""); setCustomerName(""); }} className="mt-3 text-xs font-semibold text-slate-400 underline">
            새 요청 등록하기
          </button>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="mt-5 space-y-3">
          <div>
            <label className="text-xs font-semibold text-slate-500">거래처명(선택)</label>
            <input value={customerName} onChange={(e) => setCustomerName(e.target.value)} placeholder="예: (주)네오플라테크창원" disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50" />
          </div>
          <div>
            <label className="text-xs font-semibold text-slate-500">요청 내용 *</label>
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              rows={5}
              placeholder="요청 내용을 입력해주세요"
              disabled={submitting}
              className="mt-1.5 w-full rounded-lg border border-slate-200 px-3 py-2.5 text-sm text-slate-800 placeholder:text-slate-300 focus:outline-none disabled:opacity-50"
            />
          </div>
          {error && <p className="text-xs font-semibold text-red-500">{error}</p>}
          <button type="submit" disabled={submitting} className="w-full rounded-lg py-2.5 text-xs font-bold text-white disabled:opacity-50" style={{ backgroundColor: "#dc2626" }}>
            {submitting ? "등록중..." : "긴급요청 등록"}
          </button>
        </form>
      )}
    </main>
  );
}

function GimhaeHome({ employee }) {
  const isAdmin = isElevatedRole(employee.role); // 관리자 또는 지원(15번)
  const [activeScreen, setActiveScreen] = useState(null);

  if (activeScreen === "schedule") {
    return <GimhaeScheduleScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }
  if (activeScreen === "schedule_register") {
    return <GimhaeScheduleScreen employee={employee} onBack={() => setActiveScreen(null)} initialShowRegisterForm />;
  }
  if (activeScreen === "route_optimizer") {
    return <GimhaeRouteOptimizerScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }
  if (activeScreen === "delivery_history") {
    return <GimhaeDeliveryHistoryScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }
  if (activeScreen === "customers") {
    return <GimhaeCustomerScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }
  if (activeScreen === "vehicles") {
    return <GimhaeVehicleScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }
  if (activeScreen === "fuel_dashboard") {
    return <FuelCostDashboardScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }
  if (activeScreen === "employees") {
    return <EmployeeListScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }
  if (activeScreen === "urgent_request") {
    return <GimhaeUrgentRequestScreen employee={employee} onBack={() => setActiveScreen(null)} />;
  }

  const menuCards = [
    { key: "schedule", icon: MapPin, label: "오늘일정", desc: "거래처 순회 납품 일정/완료처리", adminOnly: false },
    { key: "schedule_register", icon: PlusCircle, label: "일정 등록", desc: "신규 납품/방문 일정 빠르게 등록", adminOnly: true },
    { key: "route_optimizer", icon: Route, label: "동선 최적화", desc: "합짐 제안 + 절감 효과(거리/시간/유류비)", adminOnly: true },
    { key: "delivery_history", icon: Clock, label: "납품경로 타임라인", desc: "날짜·기사별 방문 순서 + 지도로 보기", adminOnly: true },
    { key: "customers", icon: Building2, label: "거래처정보", desc: "납품 거래처 목록 조회", adminOnly: false },
    { key: "vehicles", icon: Truck, label: "차량관리", desc: "법인·개인 차량 현황 및 보험 정보", adminOnly: false },
    { key: "urgent_request", icon: Megaphone, label: "업체 긴급요청", desc: "거래처 현장의 긴급 요청 등록", adminOnly: false },
    { key: "fuel_dashboard", icon: Fuel, label: "유류비 관리", desc: "월별 차량별 주행거리/유류비 현황", adminOnly: true },
    { key: "employees", icon: Users, label: "직원명부", desc: "전체 직원 조회", adminOnly: true },
  ];

  return (
    <main className="mx-auto max-w-3xl px-6 py-8">
      <h1 className="text-xl font-bold text-slate-900">김해공장 물류 동선 관리</h1>
      <p className="mt-1 text-sm text-slate-400">
        {employee.name}{employee.title} · {isAdmin ? "관리자 권한으로 모든 메뉴를 사용할 수 있습니다." : `${ROLE_LABELS[employee.role] || employee.role} 권한으로 오늘일정 조회/완료처리가 가능합니다.`}
      </p>

      <div className="mt-6 grid grid-cols-2 gap-3">
        {menuCards.map((card) => {
          const locked = card.adminOnly && !isAdmin;
          return (
            <button
              key={card.key}
              disabled={locked}
              onClick={() => !locked && setActiveScreen(card.key)}
              className={`flex flex-col items-start gap-2 rounded-2xl border p-4 text-left ${
                locked ? "border-slate-100 bg-slate-50 opacity-50" : "border-slate-200 bg-white shadow-sm active:bg-slate-50"
              }`}
            >
              <span className="flex h-10 w-10 items-center justify-center rounded-xl" style={{ backgroundColor: BRAND.greenSoft }}>
                <card.icon className="h-5 w-5" style={{ color: BRAND.deepGreen }} />
              </span>
              <span className="text-[15px] font-bold text-slate-900">{card.label}</span>
              <span className="text-xs text-slate-400">{card.desc}</span>
              {locked && <span className="text-[10px] font-semibold text-amber-600">관리자만 사용 가능</span>}
            </button>
          );
        })}
      </div>
    </main>
  );
}

// ────────────────────────────────────────────────────────────────────────
// ────────────────────────────────────────────────────────────────────────
// 자동로그인 — 로그인 성공 시 employee/activeSite를 localStorage에 저장해두고,
// 다음 접속(새로고침/앱 재실행) 시 그 값으로 곧바로 홈 화면을 띄운다.
// 비밀번호는 저장하지 않으며, 로그아웃 시 즉시 삭제된다.
// localStorage를 쓸 수 없는 환경(시크릿 모드 등)에서는 자동로그인만 동작하지
// 않을 뿐 매번 로그인하는 기존 방식 그대로 정상 동작한다.
// ────────────────────────────────────────────────────────────────────────
const SESSION_STORAGE_KEY = "greensync_session_v1";

function loadSavedSession() {
  try {
    const raw = localStorage.getItem(SESSION_STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (!parsed || !parsed.employee || !parsed.activeSite) return null;
    return parsed;
  } catch (err) {
    return null;
  }
}

function saveSession(employee, activeSite) {
  try {
    localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify({ employee, activeSite }));
  } catch (err) {
    // 저장 실패 시 조용히 무시 — 자동로그인만 안 될 뿐 앱 사용에는 영향 없음
  }
}

function clearSession() {
  try {
    localStorage.removeItem(SESSION_STORAGE_KEY);
  } catch (err) {
    // no-op
  }
}

// ────────────────────────────────────────────────────────────────────────
// 24번 요청 — 앱을 사용 중일 때(포그라운드) 새 알림이 생기면 화면 중앙에 팝업으로
// 띄워준다. "마지막으로 확인한 알림 시각"을 기기에 저장해두고, 그보다 최신인
// 알림이 보이면 한 번만 팝업으로 알려준다.
// (다른 앱을 쓰고 있을 때도 휴대폰 상단에 뜨는 OS 알림은 별도의 푸시 인프라
// — 서비스워커, VAPID 키, 구독 저장, Web Push 프로토콜 서버 구현 — 가
// 필요해서 이번 범위에는 포함하지 않았다. 아래 안내 메시지 참고.)
const NOTIF_LAST_SEEN_KEY = "greensync_last_notif_seen_v1";

function getLastSeenNotifTimestamp() {
  try {
    return localStorage.getItem(NOTIF_LAST_SEEN_KEY) || null;
  } catch (err) {
    return null;
  }
}

function setLastSeenNotifTimestamp(iso) {
  try {
    localStorage.setItem(NOTIF_LAST_SEEN_KEY, iso);
  } catch (err) {
    // no-op
  }
}

// ────────────────────────────────────────────────────────────────────────
// 최상위 컴포넌트 — 로그인 → (필요시) 강제 비밀번호 변경 → 근무지별 화면 분기
// ────────────────────────────────────────────────────────────────────────
export default function GreenSyncApp() {
  const [screen, setScreen] = useState(() => (loadSavedSession() ? "home" : "login")); // login | forcePasswordChange | home
  const [employee, setEmployee] = useState(() => loadSavedSession()?.employee || null);
  // 현재 화면에 보여줄 사이트. 로그인 시 employee.homeSite로 초기화되고,
  // "지원"/"관리자" 권한은 GlobalHeader의 전환 버튼으로 이 값만 바꿀 수 있다.
  // (실제 직원명부의 소속은 그대로 유지되며, 새로고침하면 homeSite로 복귀)
  const [activeSite, setActiveSite] = useState(() => loadSavedSession()?.activeSite || null);
  const [switchError, setSwitchError] = useState("");
  const [showNotifications, setShowNotifications] = useState(false);
  const [popupNotification, setPopupNotification] = useState(null);
  const [siteSwitchToast, setSiteSwitchToast] = useState(null); // 근무지 전환 완료 안내(26번)
  const siteSwitchToastTimerRef = useRef(null);

  // 24번 요청 — 앱을 켜놓고 사용하는 동안 새 알림이 생기면 화면 중앙에 팝업으로
  // 띄운다. 로그인 화면에서는 동작하지 않고, "home" 화면일 때만 일정 주기로
  // 새 알림이 있는지 확인한다.
  useEffect(() => {
    if (screen !== "home") return;
    let cancelled = false;

    // 기준 시각이 아예 없으면(최초 실행) "지금"으로 잡아서, 과거 알림이
    // 한꺼번에 쏟아지듯 팝업으로 뜨지 않게 한다.
    if (!getLastSeenNotifTimestamp()) {
      setLastSeenNotifTimestamp(new Date().toISOString());
    }

    const checkForNewNotifications = async () => {
      try {
        const list = await listNotifications();
        if (cancelled || list.length === 0) return;
        const lastSeen = getLastSeenNotifTimestamp();
        const lastSeenTime = lastSeen ? new Date(lastSeen).getTime() : 0;
        const newest = list[0]; // 서버가 항상 최신순으로 내려준다.
        if (new Date(newest.timestamp).getTime() > lastSeenTime) {
          setPopupNotification(newest);
          setLastSeenNotifTimestamp(newest.timestamp);
        }
      } catch (err) {
        // 알림 확인 실패는 조용히 무시한다(메인 화면 사용에 영향 주지 않음).
      }
    };

    const intervalId = setInterval(checkForNewNotifications, 45000);
    const firstCheckTimer = setTimeout(checkForNewNotifications, 5000);
    return () => {
      cancelled = true;
      clearInterval(intervalId);
      clearTimeout(firstCheckTimer);
    };
  }, [screen]);

  // 화면을 위로 당겼을 때 생기는 "고무줄(바운스) 스크롤"을 막는다. iOS에서 이 바운스가
  // 일어나는 동안 화면 맨 위쪽(와이파이/시간 표시 영역)이 같이 밀려 내려와 그 위에 있는
  // 헤더 버튼이 묻히면서 터치가 안 먹는 문제가 있었다(14번 요청). 앱 전체에 한 번만 적용.
  useEffect(() => {
    const styleEl = document.createElement("style");
    styleEl.setAttribute("data-greensync-global", "true");
    styleEl.textContent = `
      html, body { overscroll-behavior-y: none; height: 100%; }
      #root { min-height: 100%; }

      @keyframes greensync-site-switch {
        0% { opacity: 0; transform: translateX(14px) scale(0.99); }
        100% { opacity: 1; transform: translateX(0) scale(1); }
      }
      .greensync-site-switch {
        animation: greensync-site-switch 0.28s ease-out;
      }
    `;
    document.head.appendChild(styleEl);
    return () => { document.head.removeChild(styleEl); };
  }, []);

  // 스와이프 뒤로가기(8번 요청) — 화면 왼쪽 가장자리에서 시작해 오른쪽으로 미는
  // 동작을 감지하면, 현재 화면에 있는 "← 홈으로" 버튼을 찾아 대신 눌러준다.
  // 화면마다 별도로 손대지 않고 한 곳에서만 처리할 수 있도록, 모든 화면이 같은
  // 문구의 뒤로가기 버튼을 쓰는 기존 관례를 그대로 활용했다.
  useEffect(() => {
    const EDGE_PX = 24; // 화면 왼쪽 끝 이 범위 안에서 시작한 터치만 스와이프 뒤로가기로 인식
    const SWIPE_PX = 70; // 오른쪽으로 이 정도 이상 이동해야 "뒤로가기"로 인정
    let startX = 0;
    let startY = 0;
    let tracking = false;

    const onTouchStart = (e) => {
      const t = e.touches[0];
      if (t && t.clientX <= EDGE_PX) {
        startX = t.clientX;
        startY = t.clientY;
        tracking = true;
      } else {
        tracking = false;
      }
    };

    const onTouchEnd = (e) => {
      if (!tracking) return;
      tracking = false;
      const t = e.changedTouches[0];
      if (!t) return;
      const dx = t.clientX - startX;
      const dy = Math.abs(t.clientY - startY);
      if (dx > SWIPE_PX && dy < 60) {
        const backButton = Array.from(document.querySelectorAll("button")).find((b) => b.textContent.trim() === "← 홈으로");
        if (backButton) backButton.click();
      }
    };

    document.addEventListener("touchstart", onTouchStart, { passive: true });
    document.addEventListener("touchend", onTouchEnd, { passive: true });
    return () => {
      document.removeEventListener("touchstart", onTouchStart);
      document.removeEventListener("touchend", onTouchEnd);
    };
  }, []);

  const handleLogin = (emp, mustChangePassword) => {
    setEmployee(emp);
    setActiveSite(emp.homeSite);
    if (mustChangePassword) {
      setScreen("forcePasswordChange");
    } else {
      saveSession(emp, emp.homeSite);
      setScreen("home");
    }
  };

  const handlePasswordChanged = () => {
    saveSession(employee, activeSite);
    setScreen("home");
  };

  const handleLogout = () => {
    clearSession();
    setEmployee(null);
    setActiveSite(null);
    setScreen("login");
  };

  const handleSwitchSite = async (targetSite) => {
    setSwitchError("");
    try {
      const result = await switchSite(employee.employeeId, targetSite);
      setActiveSite(result.activeSite);
      const switchedLabel = SITES[result.activeSite]?.label || result.activeSite;
      setSiteSwitchToast(`${switchedLabel}으로 전환되었습니다.`);
      window.clearTimeout(siteSwitchToastTimerRef.current);
      siteSwitchToastTimerRef.current = window.setTimeout(() => setSiteSwitchToast(null), 1800);
    } catch (err) {
      setSwitchError(err.message || "근무지 전환 중 오류가 발생했습니다.");
    }
  };

  if (screen === "login") {
    return <LoginScreen onLogin={handleLogin} />;
  }

  if (screen === "forcePasswordChange") {
    return <ForcePasswordChangeScreen employee={employee} onChanged={handlePasswordChanged} onLogout={handleLogout} />;
  }

  // screen === "home" — activeSite(전환 가능)에 따라 창원/김해 화면으로 분기
  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      <GlobalHeader employee={employee} activeSite={activeSite} onSwitchSite={handleSwitchSite} onLogout={handleLogout} onOpenNotifications={() => setShowNotifications(true)} />
      {switchError && (
        <p className="mx-auto max-w-3xl px-6 pt-3 text-xs font-semibold text-red-500">{switchError}</p>
      )}
      {showNotifications ? (
        <NotificationScreen employee={employee} onBack={() => setShowNotifications(false)} />
      ) : activeSite === "changwon" ? (
        <div key="changwon" className="greensync-site-switch">
          <ChangwonHome employee={employee} />
        </div>
      ) : activeSite === "gimhae" ? (
        <div key="gimhae" className="greensync-site-switch">
          <GimhaeHome employee={employee} />
        </div>
      ) : (
        <main className="mx-auto max-w-md px-6 py-16 text-center">
          <p className="text-sm font-semibold text-red-500">
            근무지 정보(home_site)를 확인할 수 없습니다. 관리자에게 문의해주세요.
          </p>
        </main>
      )}

      {siteSwitchToast && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-6" style={{ pointerEvents: "none" }}>
          <div className="greensync-site-switch flex items-center gap-2 rounded-2xl px-5 py-4 text-sm font-bold text-white shadow-xl" style={{ backgroundColor: BRAND.deepGreen }}>
            <ArrowLeftRight className="h-4 w-4 flex-shrink-0" />
            {siteSwitchToast}
          </div>
        </div>
      )}

      {popupNotification && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-6">
          <div className={`w-full max-w-sm rounded-2xl bg-white p-5 shadow-xl ${isUrgentNotificationCategory(popupNotification.category) ? "border-2 border-red-300" : ""}`}>
            <p className={`text-sm font-bold ${isUrgentNotificationCategory(popupNotification.category) ? "text-red-600" : "text-slate-900"}`}>
              {popupNotification.title}
            </p>
            <p className="mt-1.5 text-sm text-slate-600">{popupNotification.content}</p>
            <p className="mt-1.5 text-[11px] text-slate-400">{popupNotification.site} · {popupNotification.actorName || "(미확인)"}</p>
            <div className="mt-4 grid grid-cols-2 gap-2">
              <button onClick={() => setPopupNotification(null)} className="rounded-lg border border-slate-200 py-2.5 text-xs font-bold text-slate-600">
                닫기
              </button>
              <button
                onClick={() => { setPopupNotification(null); setShowNotifications(true); }}
                className="rounded-lg py-2.5 text-xs font-bold text-white"
                style={{ backgroundColor: BRAND.deepGreen }}
              >
                보기
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
